import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, ZoomIn, ZoomOut, CheckCircle, BookOpen, Share2 } from 'lucide-react';
import { PYQQuestion, Language } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage = 'English' 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  // Default font size decreased by 2 (was 16, now 14)
  const [fontSize, setFontSize] = useState(14);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const handleAppBack = () => {
    onExit(); 
    return true;
  };

  useBackHandler(handleAppBack);

  useEffect(() => {
    const fetchQuestions = async () => {
        setLoading(true);
        const data = await api.getPYQs(subject, year, 'subjective');
        setQuestions(data);
        setLoading(false);
    };
    if (subject && year) {
        fetchQuestions();
    }
  }, [subject, year]);

  const currentQ = questions[currentIndex];

  // Scroll to top when question changes
  useEffect(() => {
      if (scrollRef.current) {
          scrollRef.current.scrollTop = 0;
      }
  }, [currentIndex]);

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const getTxt = (en?: string | null, hi?: string | null) => lang === 'hi' ? (hi || en) : en;

  if (loading) {
      return (
        <div className="h-full flex flex-col items-center justify-center bg-white gap-4 font-serif">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-900 font-bold text-sm uppercase tracking-widest">Opening Book...</p>
        </div>
      );
  }

  if (!questions || questions.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white p-6 text-center">
        <BookOpen size={48} className="text-gray-300 mb-4" />
        <p className="text-gray-900 font-bold text-lg mb-2">Empty Chapter</p>
        <p className="text-gray-500 text-sm mb-6">No subjective questions found for {subject} ({year}).</p>
        <button onClick={handleAppBack} className="px-8 py-3 bg-gray-900 text-white rounded-xl text-sm font-bold shadow-lg active:scale-95 transition-transform">Go Back</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-[#f8f9fa] font-sans animate-fade-in relative">

      {/* 1. Header (Fixed, High Z-Index) */}
      <div className="px-4 pb-3 pt-safe-header bg-white border-b border-gray-200 flex justify-between items-center sticky top-0 z-50 shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <button 
            onClick={handleAppBack} 
            className="w-10 h-10 flex items-center justify-center -ml-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors active:scale-95"
          >
            <ArrowLeft size={22} />
          </button>
          <div>
            <h2 className="text-lg font-black text-gray-900 leading-none tracking-tight">Subjective</h2>
            <p className="text-[10px] font-bold text-gray-500 uppercase mt-1 tracking-wide">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
            <div className="flex items-center bg-gray-100 rounded-lg border border-gray-200 p-0.5">
            <button 
                onClick={() => setFontSize(s => Math.max(12, s - 2))}
                className="w-8 h-8 flex items-center justify-center text-gray-500 hover:text-gray-900 active:bg-white rounded-md transition-all"
            >
                <ZoomOut size={16} />
            </button>
            <div className="w-[1px] h-4 bg-gray-300"></div>
            <button 
                onClick={() => setFontSize(s => Math.min(24, s + 2))}
                className="w-8 h-8 flex items-center justify-center text-gray-500 hover:text-gray-900 active:bg-white rounded-md transition-all"
            >
                <ZoomIn size={16} />
            </button>
            </div>
        </div>
      </div>

      {/* 2. Progress Strip */}
      <div className="bg-white border-b border-gray-200 px-5 py-3 flex justify-between items-center shrink-0 z-40 relative">
        <div className="flex items-center gap-2">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Q {currentIndex + 1} <span className="text-gray-300">/ {questions.length}</span></span>
        </div>

        <button 
            onClick={() => setLang(l => l==='en'?'hi':'en')} 
            className="flex items-center gap-1.5 bg-gray-900 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold shadow-md active:scale-95 transition-transform"
        >
            <i className="fa-solid fa-language text-xs"></i>
            {lang === 'en' ? 'ENGLISH' : 'HINDI'}
        </button>
      </div>

      {/* 3. Content Area (Scrollable "Paper" View) */}
      <div 
        ref={scrollRef} 
        className="flex-1 overflow-y-auto p-4 pb-32 w-full bg-[#f0f2f5]"
      >
        <div className="bg-white max-w-2xl mx-auto min-h-[60vh] p-6 md:p-10 shadow-sm border border-gray-200 rounded-xl relative">

            {/* Paper Header Line */}
            <div className="w-full h-px bg-red-100 mb-8 absolute top-8 left-0 opacity-50"></div>

            {/* Marks Badge */}
            {currentQ.marks && (
                <div className="absolute top-0 right-0 bg-gray-900 text-white px-3 py-1.5 rounded-bl-xl text-[10px] font-bold shadow-sm z-10">
                    {currentQ.marks} Marks
                </div>
            )}

            {/* Question Section */}
            <div className="mb-8 relative z-10">
                <span className="inline-block px-2 py-0.5 bg-gray-100 text-gray-500 rounded text-[10px] font-bold uppercase mb-3 border border-gray-200">
                    Question
                </span>
                <h1 
                    className={`font-bold text-gray-900 leading-normal font-sans tracking-tight`}
                    style={{ fontSize: `${fontSize + 2}px` }}
                >
                    {getTxt(currentQ.question_text_en, currentQ.question_text_hi)}
                </h1>
            </div>

            {/* Answer Section (Book Style) */}
            <div className="relative pl-6 md:pl-8 border-l-4 border-gray-200">
                {/* Decorative Icon */}
                <div className="absolute -left-[11px] -top-1 w-5 h-5 bg-gray-200 rounded-full flex items-center justify-center text-white ring-4 ring-white">
                     <span className="text-gray-500 text-[10px] font-serif font-bold italic">A</span>
                </div>

                <div className="mb-2">
                    <span className="text-gray-400 font-bold text-[10px] uppercase tracking-widest font-sans">Solution</span>
                </div>

                <div 
                    className="text-gray-900 leading-loose font-serif text-justify whitespace-pre-wrap antialiased"
                    style={{ fontSize: `${fontSize}px` }}
                >
                    {getTxt(currentQ.answer_text_en, currentQ.answer_text_hi) || getTxt(currentQ.solution_short_en, currentQ.solution_short_hi) || "Detailed answer is being prepared by our educators."}
                </div>
            </div>

            {/* Footer of Card */}
            <div className="mt-12 pt-6 border-t border-gray-100 flex items-center justify-between opacity-60">
                <span className="text-[10px] font-bold text-gray-400 uppercase">Raftaar 2026</span>
                <div className="w-12 h-1 bg-gray-100 rounded-full"></div>
            </div>

        </div>
      </div>

      {/* 4. Bottom Navigation (Fixed, High Z-Index) */}
      <div className="absolute bottom-0 w-full bg-white border-t border-gray-200 p-4 pb-safe z-50 shadow-[0_-5px_30px_rgba(0,0,0,0.08)] flex gap-4">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-4 rounded-xl font-bold text-gray-600 bg-white border-2 border-gray-200 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 active:scale-[0.98] transition-all text-sm uppercase tracking-wide"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-4 rounded-xl font-bold text-white bg-gray-900 shadow-xl shadow-gray-900/20 hover:bg-gray-800 active:scale-[0.98] transition-all text-sm uppercase tracking-wide flex items-center justify-center gap-2"
        >
            {currentIndex === questions.length - 1 ? (
                <>Finish <CheckCircle size={16} /></>
            ) : (
                'Save & Next'
            )}
        </button>
      </div>

    </div>
  );
};

