  // Stack Navigation Logic for Hardware Back Button
  const handleAppBack = () => {
    if (step === 2) {
      // Go back to Step 1
      setSelectedSubject(null);
      // Important: Also update URL to clear subject, which will trigger parent re-render and keep things in sync
      if (onUpdateSubject) onUpdateSubject(null); 
