// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  // --- 1. GLOBAL STATUS BAR MANAGEMENT ---
  useStatusBar();

  // --- DOUBLE BACK TO EXIT LOGIC (HOME SCREEN ONLY) ---
  // Only activate if no modals are open and we are on home.
  const isModalsClosed = !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen;

  useBackHandler(() => {
    if (location.pathname === '/' && isModalsClosed) {
        if (exitAttempted) {
            return false; // Let browser exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; // Trap
        }
    }
    return false; // Don't trap if not on home or modals open
  }, location.pathname === '/' && isModalsClosed);

  useEffect(() => {
    let mounted = true;
    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (error) throw error;
        if (mounted && session) {
            setSession(session);
            fetchProfile(session.user.id).catch(console.error);
        }
      } catch (error) {
        console.error("Session fail", error);
      } finally {
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session) fetchProfile(session.user.id).catch(console.error);
      else setUserProfile(null);
      setIsAppInitializing(false);
    });

    return () => { mounted = false; subscription.unsubscribe(); };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      window.history.replaceState({}, document.title);
    } else {
      setInfinityInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  // Fix: Handle PYQ Modal Open from navigation state safely
  useEffect(() => {
    const state = location.state as any;
    if (state && state.openPYQ) {
        setPyqInitialTab(state.tab || 'objective');
        setInstantOpen(true); 
        setPYQOpen(true);
        // CRITICAL: Clear state to prevent loop on subsequent renders or refreshes
        // Using navigate with replace to clean history stack without adding new entry
        navigate(location.pathname, { replace: true, state: {} });
    } else {
        setInstantOpen(false); 
    }
  }, [location, navigate]);

  const fetchProfile = async (userId: string) => {
    const data = await api.getProfile(userId);
    if (!data) {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const fullName = user?.user_metadata?.full_name || 'Student';
            const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
            const newProfile = await api.createProfile(userId, fullName, avatarUrl);
            if (newProfile) setUserProfile(newProfile);
        }
    } else {
        setUserProfile(data);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      // Using Push (default) instead of replace to allow history back to work
      setSearchParams(newParams);
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-600' : 'text-gray-400 hover:text-gray-600'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-[#f8faff] font-sans relative shadow-2xl overflow-hidden text-gray-900">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-gray-50 flex justify-between items-center sticky top-0 z-30 border-b border-gray-200 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-600 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-white p-0.5 border border-gray-200 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session.user.email}`} className="w-full h-full rounded-full" alt="User" />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' })} // Push to open
                                onOpenPYQ={() => { setInstantOpen(false); setPyqInitialTab('objective'); setPYQOpen(true); }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id); 
                                    // Navigate back to Home but with state to re-open PYQ modal at Objective tab
                                    navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => navigate('/', { replace: true, state: { openPYQ: true, tab: 'subjective' } })}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${activeSubject}`, { replace: true });
                                    } else {
                                        // For Modal based tests, go home, state will handle re-opening if needed (logic specific to modal types)
                                        navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    // Return to Home with Infinity Modal open logic
                                    const subjectParam = infinityConfig?.subject ? `&subject=${encodeURIComponent(infinityConfig.subject)}` : '';
                                    navigate(`/?mode=infinity${subjectParam}`, { replace: true, state: { returnTo: 'infinity' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <div className="p-10 text-center">Loading...</div>
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => navigate(-1)} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id}
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-gray-100 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-gray-900 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-lg">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType } from 'lucide-react';
import { api } from '../services/api';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Physics', icon: Atom, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Biology', icon: Dna, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Hindi', icon: Languages, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'English', icon: BookType, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  // Local state to track which step we are on
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);

  // Step is derived: If subject is selected, we are on Step 2. Otherwise Step 1.
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync props to state when modal opens
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        if (!initialSubject) setSelectedChapters([]);
    }
  }, [isOpen, initialSubject]);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
        alert("Minimum 2 chapters required to start.");
        return;
    }
    setCreating(true);
    await api.createPracticeSession(userId, selectedSubject, selectedChapters);
    setCreating(false);
    onStartSession(selectedSubject, selectedChapters);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: instantOpen ? 0.5 : 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black z-40"
          />

          <motion.div
            initial={{ x: instantOpen ? 0 : "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="fixed inset-y-0 right-0 w-full max-w-md bg-white z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans"
          >
            <div className="bg-white shadow-sm z-20 border-b border-gray-100 shrink-0 sticky top-0">
                <div className="pt-safe-header pb-4 px-5 flex items-center gap-3">
                    <button onClick={() => window.history.back()} className="text-gray-600 hover:text-gray-900 transition-colors p-1 -ml-2 rounded-full active:bg-gray-100">
                        <ChevronLeft size={28} strokeWidth={2.5} />
                    </button>
                    <h2 className="text-xl font-black text-gray-900 tracking-tight">
                        {step === 1 ? 'Select Subject' : 'Select Chapters'}
                    </h2>
                </div>

                <div className="px-6 pb-6">
                    <div className="flex items-center justify-between text-sm w-full">
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 1 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                {step > 1 ? <Check size={10} /> : '1'}
                            </div>
                            <span className={`${step >= 1 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Subject</span>
                        </div>
                        <div className="flex-1 h-[2px] bg-gray-100 mx-3 rounded-full"></div>
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 2 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                2
                            </div>
                            <span className={`${step >= 2 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Chapter</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 min-h-0 relative flex flex-col bg-gray-50">
              <div className="absolute inset-0 overflow-y-auto hide-scrollbar pb-safe">

              {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col min-h-full"
                >
                    <div className="p-6 space-y-4 z-10 flex-1">
                        {subjectsList.map((sub) => (
                            <div 
                            key={sub.name}
                            onClick={() => handleSubjectSelect(sub.name)}
                            className={`bg-white h-16 rounded-xl flex items-center px-4 cursor-pointer transition-all border border-gray-200 shadow-sm hover:shadow-md active:scale-[0.98]`}
                            >
                            <div className="w-10 h-10 flex items-center justify-center rounded-lg border border-sky-100 mr-4">
                                <sub.icon size={20} className={sub.color} strokeWidth={1.5} />
                            </div>
                            <div className="h-8 w-[1px] bg-gray-100 mr-4"></div>
                            <span className="font-bold text-gray-800 text-sm tracking-wide">{sub.name}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 20 }}
                    className="p-6 pb-24 flex flex-col min-h-full"
                >
                  {selectedChapters.length < 2 && (
                      <div className="mb-4 bg-red-50 border border-red-100 text-red-600 px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 shrink-0">
                          <div className="w-4 h-4 bg-red-100 rounded-full flex items-center justify-center text-red-500">!</div>
                          Minimum 2 chapters required
                      </div>
                  )}

                  <div className="flex justify-between items-center mb-4 shrink-0">
                    <h3 className="font-bold text-gray-900 text-lg">Select Chapters</h3>
                    <span className="bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-xs font-bold">
                      {selectedChapters.length}/{chapters.length}
                    </span>
                  </div>

                  {loading ? (
                    <div className="space-y-3">
                      {[1,2,3,4,5,6].map(i => <div key={i} className="h-16 bg-white rounded-xl border border-gray-100 animate-pulse" />)}
                    </div>
                  ) : (
                    <div className="space-y-3 pb-4">
                      {chapters.map((chap, idx) => {
                        const isSelected = selectedChapters.includes(chap.en);
                        return (
                          <div 
                            key={chap.en}
                            onClick={() => toggleChapter(chap.en)}
                            className={`bg-white p-4 rounded-xl border flex items-center gap-4 cursor-pointer transition-all ${isSelected ? 'border-brand-500 ring-1 ring-brand-500 shadow-sm bg-brand-50/30' : 'border-gray-200 hover:border-gray-300'}`}
                          >
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 border ${isSelected ? 'bg-brand-100 text-brand-600 border-brand-200' : 'bg-gray-50 text-gray-500 border-gray-100'}`}>
                              {idx + 1}
                            </div>
                            <div className="flex-1">
                              <h4 className={`font-bold text-sm ${isSelected ? 'text-brand-700' : 'text-gray-800'}`}>{chap.en}</h4>
                              {chap.hi && (
                                <p className="text-xs text-gray-400 font-medium mt-0.5">{chap.hi}</p>
                              )}
                              <p className="text-[10px] text-gray-300 font-medium mt-1">{chap.count} Questions</p>
                            </div>
                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${isSelected ? 'bg-brand-600 border-brand-600 text-white' : 'border-gray-300 bg-white'}`}>
                              {isSelected && <Check size={12} strokeWidth={3} />}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </motion.div>
              )}
              </div>
            </div>

            {step === 2 && (
              <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe flex gap-4 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] z-20">
                <button 
                  onClick={() => window.history.back()}
                  className="flex-1 py-3 rounded-xl font-bold text-gray-600 bg-white border border-gray-200 hover:bg-gray-50 transition-colors"
                >
                  Previous
                </button>
                <button 
                  onClick={handleStart}
                  disabled={selectedChapters.length < 2 || creating}
                  className="flex-1 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-700 transition-transform active:scale-95"
                >
                  {creating ? 'Creating...' : 'Start'}
                </button>
              </div>
            )}

          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

