// Practice Screen
const PracticeScreen = ({ onSelectChapter, navigate, profile }: { onSelectChapter: (subject: string, chapter: string) => void, navigate: any, profile: Profile | null }) => {
    const [subjects, setSubjects] = useState<string[]>([]);
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedSubject = searchParams.get('subject');

    const [chapters, setChapters] = useState<{en: string, hi: string, count: number}[]>([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
      api.getSubjects().then(setSubjects);
    }, []);

    useEffect(() => {
      if (selectedSubject) {
          setLoading(true);
          api.getChapterStats(selectedSubject).then(data => {
              setChapters(data);
              setLoading(false);
          });
      }
    }, [selectedSubject]);

    // History Logic: 
    // We rely on standard browser navigation. 
    // When a user selects a subject, we use setSearchParams (which Pushes to history).
    // The Back button will naturally go back to the list.

    return (
        <div className="h-full flex flex-col bg-white">
            <div className="sticky top-0 z-50 px-5 pb-3 pt-safe-header bg-white flex justify-between items-center border-b border-gray-200 shadow-sm">
                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => window.history.back()} 
                        className="text-gray-600 hover:text-gray-900 transition-colors p-1 -ml-1 rounded-full active:bg-gray-100"
                    >
                        <i className="fa-solid fa-chevron-left text-lg"></i>
                    </button>
                    <h2 className="text-xl font-black text-gray-900">
                        {selectedSubject || 'Practice'}
                    </h2>
                </div>
                <div className="flex items-center gap-1 text-brand-600 font-black">
                    <i className="fa-solid fa-bolt text-xs"></i>
                    <span>{profile?.weekly_xp || 0}</span>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto hide-scrollbar p-5 pb-24 animate-fade-in">
                {!selectedSubject ? (
                    <>
                        <h2 className="text-2xl font-black text-gray-900 mb-6">Select <span className="text-brand-600">Subject</span></h2>
                        <div className="grid grid-cols-2 gap-4">
                            {subjects.map(sub => (
                                <div key={sub} onClick={() => setSearchParams({ subject: sub })} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col items-center justify-center gap-2 cursor-pointer active:scale-95 transition-transform hover:shadow-md hover:border-brand-200 group">
                                    <SubjectIcon subject={sub} />
                                    <span className="font-bold text-gray-700 text-sm group-hover:text-brand-600 transition-colors">{sub}</span>
                                </div>
                            ))}
                        </div>
                    </>
                ) : (
                    <div className="space-y-3">
                        {loading ? (
                            <div className="text-center p-10 text-gray-400 text-sm font-bold animate-pulse">Loading chapters...</div>
                        ) : (
                            chapters.map((chap, idx) => (
                                <div key={idx} onClick={() => onSelectChapter(selectedSubject, chap.en)} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm active:scale-[0.98] transition-transform flex items-center justify-between cursor-pointer hover:border-brand-200 group">
                                    <div>
                                        <h4 className="font-bold text-gray-800 text-sm group-hover:text-brand-600 transition-colors">
                                            {idx + 1}. {chap.en}
                                        </h4>
                                        {chap.hi && <p className="text-xs text-gray-400 mt-1 font-medium">{chap.hi}</p>}
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors">
                                        <i className="fa-solid fa-chevron-right text-xs"></i>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

// Result Screen
const ResultScreen = ({ stats, onHome }: { stats: any, onHome: () => void }) => {
    if(!stats) return <div className="h-screen flex items-center justify-center">Loading Result...</div>;
    const score = stats.correct * 1; 

    // Strict Back Handler for Result Screen -> Previous Screen
    useBackHandler(() => {
        onHome();
        return true;
    });

    return (
        <div className="h-[100dvh] overflow-y-auto bg-white p-6 animate-slide-up pb-20 flex flex-col items-center justify-center text-center">
            <div className="w-20 h-20 bg-brand-50 rounded-full flex items-center justify-center mb-6">
                <i className="fa-solid fa-trophy text-4xl text-brand-600"></i>
            </div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Test Completed</h2>
            <p className="text-gray-500 font-medium mb-8">Great job! Here is your performance.</p>

            <div className="bg-gray-50 rounded-3xl p-8 w-full mb-8">
                <div className="text-6xl font-black mb-2 text-brand-600">{score}</div>
                <div className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-6">Total Score</div>

                <div className="grid grid-cols-2 gap-4 w-full">
                    <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm"><p className="text-2xl font-black text-green-600">{stats.correct}</p><p className="text-[10px] uppercase font-bold text-gray-400">Correct</p></div>
                    <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm"><p className="text-2xl font-black text-red-500">{stats.wrong}</p><p className="text-[10px] uppercase font-bold text-gray-400">Wrong</p></div>
                </div>
            </div>

            <button onClick={onHome} className="w-full py-4 bg-brand-600 text-white font-bold rounded-xl shadow-lg hover:scale-[1.02] transition-transform">Return to Chapters</button>
        </div>
    );
};

// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  // --- 1. GLOBAL STATUS BAR MANAGEMENT ---
  useStatusBar();

  // --- DOUBLE BACK TO EXIT LOGIC (HOME SCREEN ONLY) ---
  // Only activate if no modals are open and we are on home.
  const isModalsClosed = !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen;

  useBackHandler(() => {
    if (location.pathname === '/' && isModalsClosed) {
        if (exitAttempted) {
            return false; // Let browser exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; // Trap
        }
    }
    return false; // Don't trap if not on home or modals open
  }, location.pathname === '/' && isModalsClosed);

  useEffect(() => {
    let mounted = true;
    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (error) throw error;
        if (mounted && session) {
            setSession(session);
            fetchProfile(session.user.id).catch(console.error);
        }
      } catch (error) {
        console.error("Session fail", error);
      } finally {
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session) fetchProfile(session.user.id).catch(console.error);
      else setUserProfile(null);
      setIsAppInitializing(false);
    });

    return () => { mounted = false; subscription.unsubscribe(); };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      // Clean URL state but keep query params
      window.history.replaceState({}, document.title);
    } else {
      setInfinityInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  // Fix: Handle PYQ Modal Open from navigation state safely
  useEffect(() => {
    const state = location.state as any;
    if (state && state.openPYQ) {
        setPyqInitialTab(state.tab || 'objective');
        setInstantOpen(true); 
        setPYQOpen(true);
        // Clean state
        navigate(location.pathname, { replace: true, state: {} });
    } else {
        setInstantOpen(false); 
    }
  }, [location, navigate]);

  const fetchProfile = async (userId: string) => {
    const data = await api.getProfile(userId);
    if (!data) {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const fullName = user?.user_metadata?.full_name || 'Student';
            const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
            const newProfile = await api.createProfile(userId, fullName, avatarUrl);
            if (newProfile) setUserProfile(newProfile);
        }
    } else {
        setUserProfile(data);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams); // Pushes to history by default
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-600' : 'text-gray-400 hover:text-gray-600'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-[#f8faff] font-sans relative shadow-2xl overflow-hidden text-gray-900">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-gray-50 flex justify-between items-center sticky top-0 z-30 border-b border-gray-200 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-600 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-white p-0.5 border border-gray-200 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session.user.email}`} className="w-full h-full rounded-full" alt="User" />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' })} // Push to open
                                onOpenPYQ={() => { setInstantOpen(false); setPyqInitialTab('objective'); setPYQOpen(true); }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id); 
                                    // Navigate BACK ONE STEP (Previous Screen)
                                    navigate(-1);
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => {
                                    // Navigate BACK ONE STEP (Previous Screen)
                                    navigate(-1);
                                }}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    // Navigate BACK ONE STEP (To previous screen before test)
                                    navigate(-1);
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    // Navigate BACK ONE STEP (To previous screen before test)
                                    navigate(-1);
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    // Navigate BACK ONE STEP (To infinity modal with selected chapters)
                                    navigate(-1);
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <div className="p-10 text-center">Loading...</div>
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => navigate(-1)} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                // We do NOT close the modal state here, we just navigate away.
                // When coming back, the modal will still be "open" in background but covered, 
                // or if unmounted, it reopens via URL/State logic.
                // Ideally, close it so back button works cleanly.
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id}
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-gray-100 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-gray-900 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-lg">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, ZoomIn, ZoomOut, CheckCircle, BookOpen } from 'lucide-react';
import { PYQQuestion, Language } from '../types';
import { api } from '../services/api';

interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage = 'English' 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  // Font size state
  const [fontSize, setFontSize] = useState(16); // Increased default slightly for better readability
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  useEffect(() => {
    const fetchQuestions = async () => {
        setLoading(true);
        try {
            const data = await api.getPYQs(subject, year, 'subjective');
            setQuestions(data || []);
        } catch (e) {
            console.error(e);
            setQuestions([]);
        } finally {
            setLoading(false);
        }
    };
    if (subject && year) {
        fetchQuestions();
    }
  }, [subject, year]);

  const currentQ = questions[currentIndex];

  // Scroll to top when question changes
  useEffect(() => {
      if (scrollRef.current) {
          scrollRef.current.scrollTop = 0;
      }
  }, [currentIndex]);

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const getTxt = (en?: string | null, hi?: string | null) => lang === 'hi' ? (hi || en) : en;

  if (loading) {
      return (
        <div className="h-full flex flex-col items-center justify-center bg-white gap-4 font-serif">
            <div className="w-10 h-10 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-500 font-bold text-sm uppercase tracking-widest">Loading...</p>
        </div>
      );
  }

  if (!questions || questions.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white p-6 text-center">
        <BookOpen size={48} className="text-gray-300 mb-4" />
        <p className="text-gray-900 font-bold text-lg mb-2">Empty Chapter</p>
        <p className="text-gray-500 text-sm mb-6">No subjective questions found for {subject} ({year}).</p>
        <button onClick={onExit} className="px-8 py-3 bg-brand-600 text-white rounded-xl text-sm font-bold shadow-lg active:scale-95 transition-transform">Go Back</button>
      </div>
    );
  }

  // Safety check to prevent crash if currentQ is somehow undefined
  if (!currentQ) return null;

  return (
    <div className="h-[100dvh] flex flex-col bg-white font-sans animate-fade-in relative">

      {/* 1. Header */}
      <div className="px-4 pb-3 pt-safe-header bg-white border-b border-gray-100 flex justify-between items-center sticky top-0 z-50 shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <button 
            onClick={onExit} 
            className="w-10 h-10 flex items-center justify-center -ml-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors active:scale-95"
          >
            <ArrowLeft size={22} />
          </button>
          <div>
            <h2 className="text-lg font-black text-gray-900 leading-none tracking-tight">Subjective</h2>
            <p className="text-[10px] font-bold text-gray-400 uppercase mt-1 tracking-wide">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
            <div className="flex items-center bg-gray-50 rounded-lg border border-gray-100 p-0.5">
                <button 
                    onClick={() => setFontSize(s => Math.max(12, s - 2))}
                    className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gray-900 active:bg-white rounded-md transition-all"
                >
                    <ZoomOut size={16} />
                </button>
                <div className="w-[1px] h-4 bg-gray-200"></div>
                <button 
                    onClick={() => setFontSize(s => Math.min(24, s + 2))}
                    className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gray-900 active:bg-white rounded-md transition-all"
                >
                    <ZoomIn size={16} />
                </button>
            </div>
        </div>
      </div>

      {/* 2. Progress Strip */}
      <div className="bg-white border-b border-gray-100 px-5 py-3 flex justify-between items-center shrink-0 z-40 relative">
        <div className="flex items-center gap-2">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Q {currentIndex + 1} <span className="text-gray-300">/ {questions.length}</span></span>
        </div>

        <button 
            onClick={() => setLang(l => l==='en'?'hi':'en')} 
            className="flex items-center gap-1.5 bg-brand-50 text-brand-700 border border-brand-100 px-3 py-1.5 rounded-lg text-[10px] font-bold active:scale-95 transition-transform"
        >
            <i className="fa-solid fa-language text-xs"></i>
            {lang === 'en' ? 'ENGLISH' : 'HINDI'}
        </button>
      </div>

      {/* 3. Content Area - Clean, Book Style Text, Hidden Scrollbar */}
      <div 
        ref={scrollRef} 
        className="flex-1 overflow-y-auto p-5 pb-32 w-full bg-white hide-scrollbar"
      >
        <div className="max-w-3xl mx-auto">

            {/* Marks Badge */}
            {currentQ?.marks && (
                <div className="flex justify-end mb-4">
                    <div className="bg-gray-900 text-white px-3 py-1 rounded text-[10px] font-bold">
                        {currentQ.marks} Marks
                    </div>
                </div>
            )}

            {/* Question Section */}
            <div className="mb-6">
                <span className="inline-block px-2 py-0.5 bg-gray-100 text-gray-500 rounded text-[10px] font-bold uppercase mb-3 border border-gray-200">
                    Question
                </span>
                <h1 
                    className="font-bold text-gray-900 leading-relaxed font-sans"
                    style={{ fontSize: `${fontSize + 2}px` }}
                >
                    {getTxt(currentQ?.question_text_en, currentQ?.question_text_hi)}
                </h1>
            </div>

            {/* Separator */}
            <div className="w-full h-px bg-gray-100 my-6"></div>

            {/* Answer Section (Book Style) */}
            <div className="relative">
                <div className="mb-3 flex items-center gap-2">
                    <span className="text-brand-600 font-bold text-[10px] uppercase tracking-widest">Answer</span>
                    <div className="h-px bg-gray-100 flex-1"></div>
                </div>

                <div 
                    className="text-gray-900 font-serif text-justify whitespace-pre-wrap antialiased"
                    style={{ 
                        fontSize: `${fontSize}px`,
                        lineHeight: '1.8' 
                    }}
                >
                    {getTxt(currentQ?.answer_text_en, currentQ?.answer_text_hi) || getTxt(currentQ?.solution_short_en, currentQ?.solution_short_hi) || "Detailed answer is being prepared by our educators."}
                </div>
            </div>

        </div>
      </div>

      {/* 4. Bottom Navigation - Blue Button */}
      <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe z-50 shadow-[0_-5px_30px_rgba(0,0,0,0.05)] flex gap-4">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-3.5 rounded-xl font-bold text-gray-500 bg-white border-2 border-gray-100 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 active:scale-[0.98] transition-all text-sm uppercase tracking-wide"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-3.5 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 hover:bg-brand-700 active:scale-[0.98] transition-all text-sm uppercase tracking-wide flex items-center justify-center gap-2"
        >
            {currentIndex === questions.length - 1 ? (
                <>Finish <CheckCircle size={16} /></>
            ) : (
                'Save & Next'
            )}
        </button>
      </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType } from 'lucide-react';
import { api } from '../services/api';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Physics', icon: Atom, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Biology', icon: Dna, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Hindi', icon: Languages, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'English', icon: BookType, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  // Local state to track which step we are on
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);

  // Step is derived: If subject is selected, we are on Step 2. Otherwise Step 1.
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync props to state when modal opens
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        if (!initialSubject) setSelectedChapters([]);
    }
  }, [isOpen, initialSubject]);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
        alert("Minimum 2 chapters required to start.");
        return;
    }
    setCreating(true);
    await api.createPracticeSession(userId, selectedSubject, selectedChapters);
    setCreating(false);
    onStartSession(selectedSubject, selectedChapters);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: instantOpen ? 0.5 : 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black z-40"
          />

          <motion.div
            initial={{ x: instantOpen ? 0 : "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="fixed inset-y-0 right-0 w-full max-w-md bg-white z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans"
          >
            <div className="bg-white shadow-sm z-20 border-b border-gray-100 shrink-0 sticky top-0">
                <div className="pt-safe-header pb-4 px-5 flex items-center gap-3">
                    <button onClick={() => window.history.back()} className="text-gray-600 hover:text-gray-900 transition-colors p-1 -ml-2 rounded-full active:bg-gray-100">
                        <ChevronLeft size={28} strokeWidth={2.5} />
                    </button>
                    <h2 className="text-xl font-black text-gray-900 tracking-tight">
                        {step === 1 ? 'Select Subject' : 'Select Chapters'}
                    </h2>
                </div>

                <div className="px-6 pb-6">
                    <div className="flex items-center justify-between text-sm w-full">
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 1 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                {step > 1 ? <Check size={10} /> : '1'}
                            </div>
                            <span className={`${step >= 1 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Subject</span>
                        </div>
                        <div className="flex-1 h-[2px] bg-gray-100 mx-3 rounded-full"></div>
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 2 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                2
                            </div>
                            <span className={`${step >= 2 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Chapter</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 min-h-0 relative flex flex-col bg-gray-50">
              <div className="absolute inset-0 overflow-y-auto hide-scrollbar pb-safe">

              {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col min-h-full"
                >
                    <div className="p-6 space-y-4 z-10 flex-1">
                        {subjectsList.map((sub) => (
                            <div 
                            key={sub.name}
                            onClick={() => handleSubjectSelect(sub.name)}
                            className={`bg-white h-16 rounded-xl flex items-center px-4 cursor-pointer transition-all border border-gray-200 shadow-sm hover:shadow-md active:scale-[0.98]`}
                            >
                            <div className="w-10 h-10 flex items-center justify-center rounded-lg border border-sky-100 mr-4">
                                <sub.icon size={20} className={sub.color} strokeWidth={1.5} />
                            </div>
                            <div className="h-8 w-[1px] bg-gray-100 mr-4"></div>
                            <span className="font-bold text-gray-800 text-sm tracking-wide">{sub.name}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 20 }}
                    className="p-6 pb-24 flex flex-col min-h-full"
                >
                  {selectedChapters.length < 2 && (
                      <div className="mb-4 bg-red-50 border border-red-100 text-red-600 px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 shrink-0">
                          <div className="w-4 h-4 bg-red-100 rounded-full flex items-center justify-center text-red-500">!</div>
                          Minimum 2 chapters required
                      </div>
                  )}

                  <div className="flex justify-between items-center mb-4 shrink-0">
                    <h3 className="font-bold text-gray-900 text-lg">Select Chapters</h3>
                    <span className="bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-xs font-bold">
                      {selectedChapters.length}/{chapters.length}
                    </span>
                  </div>

                  {loading ? (
                    <div className="space-y-3">
                      {[1,2,3,4,5,6].map(i => <div key={i} className="h-16 bg-white rounded-xl border border-gray-100 animate-pulse" />)}
                    </div>
                  ) : (
                    <div className="space-y-3 pb-4">
                      {chapters.map((chap, idx) => {
                        const isSelected = selectedChapters.includes(chap.en);
                        return (
                          <div 
                            key={chap.en}
                            onClick={() => toggleChapter(chap.en)}
                            className={`bg-white p-4 rounded-xl border flex items-center gap-4 cursor-pointer transition-all ${isSelected ? 'border-brand-500 ring-1 ring-brand-500 shadow-sm bg-brand-50/30' : 'border-gray-200 hover:border-gray-300'}`}
                          >
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 border ${isSelected ? 'bg-brand-100 text-brand-600 border-brand-200' : 'bg-gray-50 text-gray-500 border-gray-100'}`}>
                              {idx + 1}
                            </div>
                            <div className="flex-1">
                              <h4 className={`font-bold text-sm ${isSelected ? 'text-brand-700' : 'text-gray-800'}`}>{chap.en}</h4>
                              {chap.hi && (
                                <p className="text-xs text-gray-400 font-medium mt-0.5">{chap.hi}</p>
                              )}
                              <p className="text-[10px] text-gray-300 font-medium mt-1">{chap.count} Questions</p>
                            </div>
                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${isSelected ? 'bg-brand-600 border-brand-600 text-white' : 'border-gray-300 bg-white'}`}>
                              {isSelected && <Check size={12} strokeWidth={3} />}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </motion.div>
              )}
              </div>
            </div>

            {step === 2 && (
              <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe flex gap-4 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] z-20">
                <button 
                  onClick={() => window.history.back()}
                  className="flex-1 py-3 rounded-xl font-bold text-gray-600 bg-white border border-gray-200 hover:bg-gray-50 transition-colors"
                >
                  Previous
                </button>
                <button 
                  onClick={handleStart}
                  disabled={selectedChapters.length < 2 || creating}
                  className="flex-1 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-700 transition-transform active:scale-95"
                >
                  {creating ? 'Creating...' : 'Start'}
                </button>
              </div>
            )}

          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Profile } from '../types';

interface HomeScreenProps {
  profile: Profile | null;
  setComingSoonTitle: (t: string) => void;
  onOpenInfinity: () => void;
  onOpenPYQ: () => void;
  onOpenDashboard: () => void;
  onOpenAchievements: () => void;
  navigate: (path: string) => void;
}

export const HomeScreen: React.FC<HomeScreenProps> = ({ 
  profile, 
  setComingSoonTitle, 
  onOpenInfinity, 
  onOpenPYQ, 
  onOpenDashboard, 
  onOpenAchievements, 
  navigate 
}) => {
  const [activeSlide, setActiveSlide] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  // Swipe Logic State
  const [touchStart, setTouchStart] = useState<number>(0);
  const [touchCurrent, setTouchCurrent] = useState<number>(0);
  const [isDragging, setIsDragging] = useState(false);

  const autoSlideInterval = useRef<ReturnType<typeof setInterval> | null>(null);

  // Slide data
  const slides = [
    {
      id: 'brand',
      isHero: true,
      bg: 'bg-gray-900', 
      btn: 'Start Practice',
      action: () => navigate('/practice'),
      overlay: 'bg-gradient-to-br from-gray-900 via-gray-800 to-black'
    },
    {
      id: 'mission_2026',
      bg: 'bg-indigo-900',
      image: 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?auto=format&fit=crop&q=80&w=800',
      title: 'Dream 450+ Marks',
      subtitle: 'BSEB 2026 • Starts 2 Feb',
      desc: '25,000+ Objectives.',
      btn: 'Start Journey',
      action: () => navigate('/practice'),
      overlay: 'bg-gradient-to-t from-black via-black/60 to-transparent'
    },
    {
      id: 'builder',
      bg: 'bg-brand-600',
      image: 'https://images.unsplash.com/photo-1555099962-4199c345e5dd?auto=format&fit=crop&q=80&w=800', 
      profileImg: 'https://raw.githubusercontent.com/socialinfi321-svgph/superkar-reviews/main/IMG_20260106_085046.jpg', 
      title: 'Prem Kashyap',
      subtitle: 'Builder of Raftaar',
      desc: 'Coding the future of education.',
      btn: 'Donate',
      link: 'https://socialinfi321-svgph.github.io/komal-caterers/',
      overlay: 'bg-gradient-to-t from-black via-black/80 to-transparent'
    },
    {
      id: 'telegram',
      bg: 'bg-blue-500',
      image: null,
      isTelegram: true,
      title: 'Join Telegram',
      subtitle: 'Daily Quizzes',
      desc: 'Get exclusive notes and daily quizzes.',
      btn: 'Join Channel',
      link: 'https://t.me/raftartestseries',
      overlay: 'bg-gradient-to-r from-blue-600/95 to-cyan-500/95'
    }
  ];

  // Auto Slider Logic
  useEffect(() => {
    if (isPaused || isDragging) return;

    autoSlideInterval.current = setInterval(() => {
        setActiveSlide(prev => (prev + 1) % slides.length);
    }, 5000);

    return () => {
        if (autoSlideInterval.current) clearInterval(autoSlideInterval.current);
    };
  }, [slides.length, isPaused, isDragging]);

  // Touch Handlers for Manual Swipe with Drag Visualization
  const onTouchStart = (e: React.TouchEvent) => {
    setIsPaused(true);
    setIsDragging(true);
    setTouchStart(e.targetTouches[0].clientX);
    setTouchCurrent(e.targetTouches[0].clientX);
  }

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchCurrent(e.targetTouches[0].clientX);
  }

  const onTouchEnd = () => {
    setIsDragging(false);
    const diff = touchStart - touchCurrent;
    const threshold = 50; // Minimum px distance to trigger slide change

    if (Math.abs(diff) > threshold) {
        if (diff > 0) {
           // Swipe Left -> Next Slide
           setActiveSlide(prev => (prev + 1) % slides.length);
        } else {
           // Swipe Right -> Prev Slide
           setActiveSlide(prev => (prev - 1 + slides.length) % slides.length);
        }
    }

    // Reset Drag State
    setTouchStart(0);
    setTouchCurrent(0);

    // Resume auto-slide after interaction
    setTimeout(() => setIsPaused(false), 5000);
  }

  // Calculate transform with visual drag offset
  const dragOffset = isDragging ? touchCurrent - touchStart : 0;

  return (
    <div className="space-y-6 pb-24 pt-4 animate-fade-in">

        {/* Rounded Premium Slider */}
        <div className="px-5">
            <div 
                className="rounded-3xl overflow-hidden shadow-xl shadow-brand-900/10 relative h-[180px] touch-pan-y"
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
            >
                {/* Slider Track */}
                <div 
                    className="flex h-full" 
                    style={{ 
                        transform: `translateX(calc(-${activeSlide * 100}% + ${dragOffset}px))`,
                        transition: isDragging ? 'none' : 'transform 0.5s ease-out'
                    }}
                >
                    {slides.map((slide, idx) => (
                        <div key={idx} className="min-w-full relative h-full flex flex-col justify-end p-5 overflow-hidden select-none">
                            {/* Background & Overlay */}
                            <div className="absolute inset-0 z-0 pointer-events-none">
                                {slide.image ? (
                                    <img src={slide.image} className="w-full h-full object-cover" alt="slide" />
                                ) : (
                                    <div className={`w-full h-full ${slide.bg}`}></div>
                                )}
                                <div className={`absolute inset-0 z-10 ${slide.overlay}`}></div>

                                {/* Telegram Pattern */}
                                {slide.isTelegram && (
                                    <div className="absolute inset-0 opacity-10 grid grid-cols-6 gap-4 p-4 transform -rotate-12">
                                        {[...Array(24)].map((_, i) => (
                                            <i key={i} className="fa-brands fa-telegram text-4xl text-white"></i>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Top Right Profile Image (For Builder Slide) */}
                            {(slide as any).profileImg && (
                                <div className="absolute top-4 right-4 z-20 flex flex-col items-end animate-fade-in">
                                    <div className="w-[110px] h-[110px] rounded-full border-4 border-white/30 shadow-2xl overflow-hidden bg-white/10 backdrop-blur-md">
                                        <img src={(slide as any).profileImg} className="w-full h-full object-cover" alt="Profile" />
                                    </div>
                                </div>
                            )}

                            {/* Content */}
                            {slide.isHero ? (
                                <div className="relative z-20 flex flex-col items-center justify-center h-full text-center">
                                    <div className="flex items-center gap-2 mb-2">
                                        <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-lg transform -rotate-6">
                                            <span className="text-gray-900 font-black text-xl font-sans">R</span>
                                        </div>
                                        <h2 className="text-3xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-blue-200 via-white to-blue-200 drop-shadow-sm">RAFTAAR</h2>
                                    </div>
                                    <div className="flex flex-wrap justify-center gap-2 text-[8px] font-bold text-white/90 uppercase tracking-widest mb-4">
                                        <span className="bg-white/10 px-2 py-1 rounded border border-white/10">Infinity Practice</span>
                                        <span className="bg-white/10 px-2 py-1 rounded border border-white/10">Live Mock Test</span>
                                    </div>
                                    <button onClick={slide.action} className="bg-white text-gray-900 px-6 py-2 rounded-full text-[10px] font-black shadow-lg hover:scale-105 transition-transform uppercase tracking-wider">Start Now</button>
                                </div>
                            ) : (
                                <div className="relative z-20 text-white">
                                    <h2 className="text-xl font-black mb-1 tracking-tight drop-shadow-md">{slide.title}</h2>
                                    <div className="inline-block bg-white/20 backdrop-blur-sm px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest mb-2 border border-white/20">
                                        {slide.subtitle}
                                    </div>
                                    <p className="text-xs opacity-90 leading-relaxed mb-3 max-w-[90%] font-medium text-gray-100 line-clamp-2">{slide.desc}</p>

                                    {slide.link ? (
                                        <a href={slide.link} target="_blank" rel="noreferrer" className="inline-block bg-white text-gray-900 px-4 py-2 rounded-lg text-[10px] font-bold shadow-md hover:scale-105 transition-transform">
                                            {slide.btn}
                                        </a>
                                    ) : (
                                        <button onClick={slide.action} className="bg-white text-gray-900 px-4 py-2 rounded-lg text-[10px] font-bold shadow-md hover:scale-105 transition-transform">
                                            {slide.btn}
                                        </button>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Dots Indicator */}
                <div className="absolute bottom-4 right-4 z-30 flex gap-1.5">
                    {slides.map((_, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => { setActiveSlide(idx); setIsPaused(true); setTimeout(() => setIsPaused(false), 5000); }}
                            className={`h-1 rounded-full transition-all duration-300 cursor-pointer ${activeSlide === idx ? 'w-4 bg-white' : 'w-1 bg-white/40'}`}
                        ></div>
                    ))}
                </div>
            </div>
        </div>

        {/* 4-Grid Menu */}
        <div className="px-5">
            <h3 className="text-gray-500 font-bold text-xs uppercase tracking-widest mb-3 ml-1">Quick Access</h3>
            <div className="grid grid-cols-2 gap-3">
                {/* Infinity Practice */}
                <div onClick={onOpenInfinity} className="bg-gradient-to-br from-purple-600 to-indigo-700 p-4 rounded-3xl shadow-lg shadow-purple-200 active:scale-95 transition-transform flex flex-col items-center justify-center text-center h-32 cursor-pointer relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-20 h-20 bg-white/10 rounded-full blur-xl -mr-5 -mt-5"></div>
                    <div className="w-10 h-10 bg-white/20 backdrop-blur-sm rounded-xl flex items-center justify-center mb-2 text-white border border-white/20">
