// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false);
  const [pyqRestoreSubject, setPyqRestoreSubject] = useState<string | null>(null); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  // --- 1. GLOBAL STATUS BAR MANAGEMENT ---
  useStatusBar();

  // --- DOUBLE BACK TO EXIT LOGIC (HOME SCREEN ONLY) ---
  const isModalsClosed = !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen;

  useBackHandler(() => {
    if (location.pathname === '/' && isModalsClosed) {
        if (exitAttempted) {
            return false; // Let browser exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; // Trap
        }
    }
    return false; // Don't trap if not on home or modals open
  }, location.pathname === '/' && isModalsClosed);

  useEffect(() => {
    let mounted = true;

    // Failsafe timeout to prevent infinite loading screen
    const timeout = setTimeout(() => {
        if (mounted && isAppInitializing) {
            console.warn("Session restore timed out - forcing app load");
            setIsAppInitializing(false);
        }
    }, 3000); // 3 seconds max wait

    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();

        if (mounted) {
            if (session) {
                setSession(session);
                if (session.user?.id) {
                    fetchProfile(session.user.id).catch(err => console.error("Profile fetch error:", err));
                }
            }
            setIsAppInitializing(false);
        }
      } catch (error) {
        console.error("Critical session failure:", error);
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session && session.user?.id) {
          fetchProfile(session.user.id).catch(console.error);
      } else {
          setUserProfile(null);
      }
      setIsAppInitializing(false);
    });

    return () => { 
        mounted = false; 
        clearTimeout(timeout);
        subscription.unsubscribe(); 
    };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  // --- STATE RESTORATION LOGIC ---
  useEffect(() => {
    const state = location.state as any;

    // 1. Restore Infinity Practice State
    if (state && state.returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      // Clear state after restoring
      window.history.replaceState({}, document.title);
    } 
    // 2. Restore PYQ State
    else if (state && state.returnTo === 'pyq') {
        setPyqInitialTab(state.tab || 'objective');
        if(state.subject) setPyqRestoreSubject(state.subject);
        setInstantOpen(true); 
        setPYQOpen(true);
        window.history.replaceState({}, document.title);
    }
    else {
      setInfinityInstantOpen(false);
      setInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  const fetchProfile = async (userId: string) => {
    if (!userId) return;
    try {
        const data = await api.getProfile(userId);
        if (!data) {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                const fullName = user?.user_metadata?.full_name || 'Student';
                const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
                const newProfile = await api.createProfile(userId, fullName, avatarUrl);
                if (newProfile) setUserProfile(newProfile);
            }
        } else {
            setUserProfile(data);
        }
    } catch (e) {
        console.error("Error fetching profile", e);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams);
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-600' : 'text-gray-400 hover:text-gray-600'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-[#f8faff] font-sans relative shadow-2xl overflow-hidden text-gray-900">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-gray-50 flex justify-between items-center sticky top-0 z-30 border-b border-gray-200 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-600 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-white p-0.5 border border-gray-200 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img 
                            src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.email ?? 'student'}`} 
                            className="w-full h-full rounded-full" 
                            alt="User" 
                        />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' })} 
                                onOpenPYQ={() => { 
                                    setInstantOpen(false); 
                                    setPyqInitialTab('objective'); 
                                    setPyqRestoreSubject(null);
                                    setPYQOpen(true); 
                                }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id);
                                    const subj = new URLSearchParams(location.search).get('subject'); 
                                    // RESTORE STATE: Go back to PYQ Modal, Step 2 (Year Select) for this subject
                                    navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'objective', subject: subj } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => {
                                     const subj = new URLSearchParams(location.search).get('subject');
                                     navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'subjective', subject: subj } });
                                }}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${activeSubject}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    const subjectParam = infinityConfig?.subject ? `&subject=${encodeURIComponent(infinityConfig.subject)}` : '';
                                    // RESTORE STATE: Return to Infinity Modal
                                    navigate(`/?mode=infinity${subjectParam}`, { replace: true, state: { returnTo: 'infinity' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <Navigate to="/" replace />
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => navigate(-1)} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            initialSubject={pyqRestoreSubject}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id || ''} 
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-gray-100 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-gray-900 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-lg">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType } from 'lucide-react';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Physics', icon: Atom, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Biology', icon: Dna, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'Hindi', icon: Languages, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
  { name: 'English', icon: BookType, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-200' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  // Local state to track which step we are on
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);

  // Step is derived: If subject is selected, we are on Step 2. Otherwise Step 1.
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync props to state when modal opens
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        if (!initialSubject) setSelectedChapters([]);
    }
  }, [isOpen, initialSubject]);

  // Handle Back Button Logic - Hierarchy: Chapters -> Subjects -> Close
  useBackHandler(() => {
    if (!isOpen) return false;

    if (step === 2) {
      setSelectedSubject(null);
      if(onUpdateSubject) onUpdateSubject(null);
      return true; // Trap the back event
    } else {
      onClose(); // Close modal
      return true; // Trap the back event
    }
  }, isOpen);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
        alert("Minimum 2 chapters required to start.");
        return;
    }
    setCreating(true);
    await api.createPracticeSession(userId, selectedSubject, selectedChapters);
    setCreating(false);
    onStartSession(selectedSubject, selectedChapters);
  };

  const handleManualBack = () => {
      if (step === 2) {
          setSelectedSubject(null);
          if(onUpdateSubject) onUpdateSubject(null);
      } else {
          onClose();
      }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: instantOpen ? 0.5 : 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black z-40"
          />

          <motion.div
            initial={{ x: instantOpen ? 0 : "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="fixed inset-y-0 right-0 w-full max-w-md bg-white z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans"
          >
            <div className="bg-white shadow-sm z-20 border-b border-gray-100 shrink-0 sticky top-0">
                <div className="pt-safe-header pb-4 px-5 flex items-center gap-3">
                    <button onClick={handleManualBack} className="text-gray-600 hover:text-gray-900 transition-colors p-1 -ml-2 rounded-full active:bg-gray-100">
                        <ChevronLeft size={28} strokeWidth={2.5} />
                    </button>
                    <h2 className="text-xl font-black text-gray-900 tracking-tight">
                        {step === 1 ? 'Select Subject' : 'Select Chapters'}
                    </h2>
                </div>

                <div className="px-6 pb-6">
                    <div className="flex items-center justify-between text-sm w-full">
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 1 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                {step > 1 ? <Check size={10} /> : '1'}
                            </div>
                            <span className={`${step >= 1 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Subject</span>
                        </div>
                        <div className="flex-1 h-[2px] bg-gray-100 mx-3 rounded-full"></div>
                        <div className="flex items-center gap-2">
                            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${step >= 2 ? 'bg-black text-white' : 'bg-gray-200 text-gray-500'}`}>
                                2
                            </div>
                            <span className={`${step >= 2 ? 'text-gray-900 font-bold' : 'text-gray-400 font-medium'}`}>Chapter</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 min-h-0 relative flex flex-col bg-gray-50">
              <div className="absolute inset-0 overflow-y-auto hide-scrollbar pb-safe">

              {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col min-h-full"
                >
                    <div className="p-6 space-y-4 z-10 flex-1">
                        {subjectsList.map((sub) => (
                            <div 
                            key={sub.name}
                            onClick={() => handleSubjectSelect(sub.name)}
                            className={`bg-white h-16 rounded-xl flex items-center px-4 cursor-pointer transition-all border border-gray-200 shadow-sm hover:shadow-md active:scale-[0.98]`}
                            >
                            <div className="w-10 h-10 flex items-center justify-center rounded-lg border border-sky-100 mr-4">
                                <sub.icon size={20} className={sub.color} strokeWidth={1.5} />
                            </div>
                            <div className="h-8 w-[1px] bg-gray-100 mr-4"></div>
                            <span className="font-bold text-gray-800 text-sm tracking-wide">{sub.name}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>
              )}

              {step === 2 && (
                <motion.div 
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 20 }}
                    className="p-6 pb-24 flex flex-col min-h-full"
                >
                  {selectedChapters.length < 2 && (
                      <div className="mb-4 bg-red-50 border border-red-100 text-red-600 px-4 py-2 rounded-lg text-xs font-bold flex items-center gap-2 shrink-0">
                          <div className="w-4 h-4 bg-red-100 rounded-full flex items-center justify-center text-red-500">!</div>
                          Minimum 2 chapters required
                      </div>
                  )}

                  <div className="flex justify-between items-center mb-4 shrink-0">
                    <h3 className="font-bold text-gray-900 text-lg">Select Chapters</h3>
                    <span className="bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-xs font-bold">
                      {selectedChapters.length}/{chapters.length}
                    </span>
                  </div>

                  {loading ? (
                    <div className="space-y-3">
                      {[1,2,3,4,5,6].map(i => <div key={i} className="h-16 bg-white rounded-xl border border-gray-100 animate-pulse" />)}
                    </div>
                  ) : (
                    <div className="space-y-3 pb-4">
                      {chapters.map((chap, idx) => {
                        const isSelected = selectedChapters.includes(chap.en);
                        return (
                          <div 
                            key={chap.en}
                            onClick={() => toggleChapter(chap.en)}
                            className={`bg-white p-4 rounded-xl border flex items-center gap-4 cursor-pointer transition-all ${isSelected ? 'border-brand-500 ring-1 ring-brand-500 shadow-sm bg-brand-50/30' : 'border-gray-200 hover:border-gray-300'}`}
                          >
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 border ${isSelected ? 'bg-brand-100 text-brand-600 border-brand-200' : 'bg-gray-50 text-gray-500 border-gray-100'}`}>
                              {idx + 1}
                            </div>
                            <div className="flex-1">
                              <h4 className={`font-bold text-sm ${isSelected ? 'text-brand-700' : 'text-gray-800'}`}>{chap.en}</h4>
                              {chap.hi && (
                                <p className="text-xs text-gray-400 font-medium mt-0.5">{chap.hi}</p>
                              )}
                              <p className="text-[10px] text-gray-300 font-medium mt-1">{chap.count} Questions</p>
                            </div>
                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${isSelected ? 'bg-brand-600 border-brand-600 text-white' : 'border-gray-300 bg-white'}`}>
                              {isSelected && <Check size={12} strokeWidth={3} />}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </motion.div>
              )}
              </div>
            </div>

            {step === 2 && (
              <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe flex gap-4 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] z-20">
                <button 
                  onClick={handleManualBack}
                  className="flex-1 py-3 rounded-xl font-bold text-gray-600 bg-white border border-gray-200 hover:bg-gray-50 transition-colors"
                >
                  Previous
                </button>
                <button 
                  onClick={handleStart}
                  disabled={selectedChapters.length < 2 || creating}
                  className="flex-1 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-700 transition-transform active:scale-95"
                >
                  {creating ? 'Creating...' : 'Start'}
                </button>
              </div>
            )}

          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Atom, FlaskConical, Calculator, Dna, Languages, BookType, Sparkles } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

const subjectsList = [
  { name: 'Physics', icon: Atom, color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-teal-600', bg: 'bg-teal-50', border: 'border-teal-100' },
  { name: 'Maths', icon: Calculator, color: 'text-indigo-600', bg: 'bg-indigo-50', border: 'border-indigo-100' },
  { name: 'Biology', icon: Dna, color: 'text-rose-600', bg: 'bg-rose-50', border: 'border-rose-100' },
  { name: 'Hindi', icon: Languages, color: 'text-orange-600', bg: 'bg-orange-50', border: 'border-orange-100' },
  { name: 'English', icon: BookType, color: 'text-violet-600', bg: 'bg-violet-50', border: 'border-violet-100' },
];

const yearsList = Array.from({ length: 16 }, (_, i) => 2010 + i).reverse();

interface PYQDashboardProps {
  isOpen: boolean;
  onClose: () => void;
  initialTab?: 'objective' | 'subjective';
  initialSubject?: string | null;
  instantOpen?: boolean;
  onSelectYear: (subject: string, year: number, type: 'objective' | 'subjective') => void;
}

export const PYQDashboard: React.FC<PYQDashboardProps> = ({ 
    isOpen, 
    onClose, 
    onSelectYear, 
    initialTab = 'objective', 
    initialSubject = null,
    instantOpen = false 
}) => {
  const [activeTab, setActiveTab] = useState<'objective' | 'subjective'>(initialTab);
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject);

  useEffect(() => {
    if (isOpen) {
      setActiveTab(initialTab);
      // Only set subject if explicitly passed, otherwise let it be null (root list)
      if (initialSubject) setSelectedSubject(initialSubject);
    }
  }, [isOpen, initialTab, initialSubject]);

  // --- STRICT HIERARCHY NAVIGATION ---
  const handleAppBack = () => {
    if (!isOpen) return false;

    // 1. If Subject Selected (Year View) -> Go to Subject Selection
    if (selectedSubject) {
      setSelectedSubject(null);
      return true; // Trap
    }

    // 2. If Subjective Tab active -> Go to Objective Tab
    if (activeTab === 'subjective') {
        setActiveTab('objective');
        return true; // Trap
    }

    // 3. If Subject Selection (Objective) -> Close Modal (Go Home)
    onClose();
    return true; // Trap
  };

  useBackHandler(handleAppBack, isOpen);

  const handleSubjectClick = (subject: string) => {
    setSelectedSubject(subject);
  };

  const handleYearClick = (year: number) => {
    if (selectedSubject) {
      onSelectYear(selectedSubject, year, activeTab);
    }
  };

  return (
    <AnimatePresence>
        {isOpen && (
            <>
                <motion.div 
                    initial={{ opacity: instantOpen ? 0.5 : 0 }} 
                    animate={{ opacity: 0.5 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 bg-black z-40" 
                />

                <motion.div
                    initial={{ x: instantOpen ? 0 : "100%" }}
                    animate={{ x: 0 }}
                    exit={{ x: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300 }}
                    className="fixed inset-y-0 right-0 w-full max-w-md bg-[#f8faff] z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans"
                >
                    <div className="absolute inset-0 z-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                    {/* Header with Safe Area (pt-safe-header) */}
                    <div className="px-5 pb-4 pt-safe-header bg-white/80 backdrop-blur-sm border-b border-gray-100 flex items-center gap-3 sticky top-0 z-50 shadow-sm shrink-0">
                        <button onClick={handleAppBack} className="w-9 h-9 flex items-center justify-center rounded-full bg-gray-50 text-gray-600 hover:bg-gray-100 border border-gray-200 transition-colors -ml-1 active:scale-95">
                            <ChevronLeft size={24} />
                        </button>
                        <h2 className="text-xl font-black text-gray-900 tracking-tight">Practice PYQs</h2>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 pb-24 z-10 hide-scrollbar pb-safe">

                        {/* Tabs */}
                        <div className="flex bg-white p-1.5 rounded-2xl mb-8 border border-gray-100 shadow-sm isolate">
                        {(['objective', 'subjective'] as const).map((tab) => {
                            const isActive = activeTab === tab;
                            return (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`flex-1 py-3 text-sm font-bold text-center relative transition-colors duration-200 ${isActive ? 'text-white' : 'text-gray-500 hover:text-gray-700'}`}
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                {isActive && (
                                <motion.div
                                    layoutId="active-tab-pill"
                                    className="absolute inset-0 bg-gray-900 rounded-xl shadow-md -z-10"
                                    transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                />
                                )}
                                <span className="relative z-10 capitalize">{tab}</span>
                            </button>
                            );
                        })}
                        </div>

                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 pl-1">Select Subject</h3>

                        <div className="relative min-h-[400px]"> 
                            <AnimatePresence mode='wait' initial={false}>
                                <motion.div
                                    key={activeTab}
                                    initial={{ x: 10, opacity: 0 }}
                                    animate={{ x: 0, opacity: 1 }}
                                    exit={{ x: -10, opacity: 0 }}
                                    transition={{ duration: 0.2 }}
                                    className="grid grid-cols-2 gap-4 w-full"
                                >
                                {subjectsList.map((sub) => (
                                    <div 
                                    key={sub.name} 
                                    onClick={() => handleSubjectClick(sub.name)}
                                    className={`bg-white p-4 rounded-2xl border ${sub.border} shadow-sm hover:shadow-md active:scale-[0.97] transition-all cursor-pointer flex flex-col justify-between h-40 group relative overflow-hidden`}
                                    >
                                        <div className={`absolute inset-0 ${sub.bg} opacity-0 group-hover:opacity-50 transition-opacity duration-300`}></div>
                                        <div className="relative z-10">
                                            <div className={`w-10 h-10 rounded-xl ${sub.bg} flex items-center justify-center ${sub.color} mb-3 border ${sub.border}`}>
                                                <sub.icon size={20} strokeWidth={2.5} />
                                            </div>
                                            <span className="font-black text-gray-800 text-lg tracking-tight block">{sub.name}</span>
                                            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wide">BSEB 2010-2025</span>
                                        </div>
                                        <div className="relative z-10 flex items-center gap-1 text-[10px] font-bold text-gray-500 group-hover:text-gray-700 transition-colors mt-auto pt-2 border-t border-gray-50">
                                            <Sparkles size={10} className="text-yellow-500" />
                                            <span>Practice PYQs</span>
                                        </div>
                                    </div>
                                ))}
                                </motion.div>
                            </AnimatePresence>
                        </div>
                    </div>

                    <AnimatePresence>
                        {selectedSubject && (
                        <>
                            <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 0.3 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setSelectedSubject(null)}
                            className="absolute inset-0 bg-black z-40"
                            />

                            <motion.div
                            initial={{ y: "100%" }}
                            animate={{ y: 0 }}
                            exit={{ y: "100%" }}
                            transition={{ type: "spring", damping: 25, stiffness: 300 }}
                            className="absolute bottom-0 left-0 right-0 z-50 rounded-t-[2rem] overflow-hidden"
                            >
                            <div className="bg-white/90 backdrop-blur-xl p-6 pb-safe border-t border-gray-200 shadow-[0_-10px_40px_rgba(0,0,0,0.1)]">
                                <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 mt-2"></div>
                                <h3 className="text-xl font-black text-gray-900 mb-2 text-center">Select Year</h3>
                                <p className="text-gray-500 text-sm text-center mb-6">
                                Practice <span className="font-bold text-gray-900 capitalize">{activeTab}</span> PYQs for <span className="font-bold text-brand-600">{selectedSubject}</span>
                                </p>
                                <div className="flex overflow-x-auto gap-3 pb-6 px-2 hide-scrollbar snap-x">
                                {yearsList.map((year) => (
                                    <button
                                    key={year}
                                    onClick={() => handleYearClick(year)}
                                    className="snap-center shrink-0 w-20 h-14 rounded-2xl bg-white border border-gray-200 shadow-sm hover:border-brand-300 hover:shadow-md flex items-center justify-center text-lg font-bold text-gray-700 transition-all active:scale-95 active:bg-gray-50"
                                    >
                                    {year}
                                    </button>
                                ))}
                                </div>
                            </div>
                            </motion.div>
                        </>
                        )}
                    </AnimatePresence>
                </motion.div>
            </>
        )}
    </AnimatePresence>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Clock, ArrowLeft, AlertTriangle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Question, Language, TestSubmission } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityTestScreenProps {
  userId: string;
  selectedChapters?: string[];
  subject: string;
  isPYQ?: boolean;
  pyqYear?: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

const shuffleArray = (array: Question[]) => {
  return array.map(value => ({ value, sort: Math.random() }))
              .sort((a, b) => a.sort - b.sort)
              .map(({ value }) => value);
};

export const InfinityTestScreen: React.FC<InfinityTestScreenProps> = ({ 
    userId, 
    selectedChapters, 
    subject, 
    onExit,
    isPYQ = false,
    pyqYear,
    defaultLanguage = 'English'
}) => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  const [isTestFinished, setIsTestFinished] = useState(false);
  const [showExitModal, setShowExitModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [roundCycle, setRoundCycle] = useState<1 | 2 | 3>(1);
  const seenIdsRef = useRef<Set<number>>(new Set()); 
  const hasFetchedNextRound = useRef<boolean>(false);
  const allQuestionsExhausted = useRef<boolean>(false);
  const questionStartTimeRef = useRef<number>(Date.now());
  const scrollRef = useRef<HTMLDivElement>(null);

  const [answers, setAnswers] = useState<Record<number, string>>({}); 
  const [visitedIndices, setVisitedIndices] = useState<Set<number>>(new Set([0]));
  const [elapsedTime, setElapsedTime] = useState(0); 
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  // --- STRICT HIERARCHY NAVIGATION ---
  const handleAppBack = () => {
    // 1. If Exit Modal Open -> Close it (Return to Test)
    if (showExitModal) {
      setShowExitModal(false);
      return true;
    }

    // 2. If Test Finished -> Trigger Exit (Go to Modal/Home)
    if (isTestFinished) {
      onExit();
      return true;
    }

    // 3. If Submitting -> Do nothing (Trap)
    if (isSubmitting) {
      return true; 
    }

    // 4. Default -> Open Exit Modal
    setShowExitModal(true);
    return true;
  };

  useBackHandler(handleAppBack, true);

  useEffect(() => {
    setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const getQuantityForRound = (cycle: number) => {
      const N = selectedChapters?.length || 1;
      if (cycle === 1) return Math.max(1, N - 1);
      if (cycle === 2) return N;
      return N + 1; 
  };

  useEffect(() => {
    const initData = async () => {
        setLoading(true);
        try {
            if (isPYQ && pyqYear) {
                const data = await api.getPYQs(subject, pyqYear, 'objective');
                if (data.length > 0) {
                    setQuestions(data);
                    allQuestionsExhausted.current = true;
                } else {
                    setFetchError(`No objective questions found for ${subject} ${pyqYear}.`);
                }
            } else if (selectedChapters && selectedChapters.length > 0) {
                const quantity = getQuantityForRound(1);
                const newQuestions = await api.fetchInfinityBatch(selectedChapters, [], quantity);

                if (newQuestions.length > 0) {
                    const randomizedQuestions = shuffleArray(newQuestions);
                    setQuestions(randomizedQuestions);
                    randomizedQuestions.forEach(q => seenIdsRef.current.add(q.id));
                    setRoundCycle(2); 
                } else {
                    setFetchError("No questions found for these chapters.");
                }
            } else {
                setFetchError("Invalid configuration.");
            }
        } catch (err) {
            console.error(err);
            setFetchError("Failed to load questions.");
        } finally {
            setLoading(false);
        }
    };

    initData();
  }, [selectedChapters, userId, isPYQ, subject, pyqYear]);

  useEffect(() => {
    if (isPYQ) return;
    if (loading || loadingMore || isTestFinished || allQuestionsExhausted.current) return;

    if (currentIndex >= questions.length - 3 && !hasFetchedNextRound.current) {
        loadNextRound();
    }
  }, [currentIndex, questions.length, loading, loadingMore, isTestFinished, isPYQ]);

  const loadNextRound = async () => {
      if (!selectedChapters) return;
      hasFetchedNextRound.current = true;
      setLoadingMore(true);
      try {
          const quantity = getQuantityForRound(roundCycle);
          const currentSeenIds = Array.from(seenIdsRef.current) as number[];
          const newBatch = await api.fetchInfinityBatch(selectedChapters, currentSeenIds, quantity);

          if (newBatch.length > 0) {
              const randomizedBatch = shuffleArray(newBatch);
              setQuestions(prev => [...prev, ...randomizedBatch]);
              randomizedBatch.forEach(q => seenIdsRef.current.add(q.id));
              setRoundCycle(prev => (prev === 3 ? 1 : prev + 1) as 1 | 2 | 3);
              hasFetchedNextRound.current = false;
          } else {
              allQuestionsExhausted.current = true;
              hasFetchedNextRound.current = true;
          }
      } catch (err) {
          hasFetchedNextRound.current = false;
      } finally {
          setLoadingMore(false);
      }
  };

  useEffect(() => {
    if (loading || isTestFinished) return;
    const interval = setInterval(() => {
      setElapsedTime(prev => prev + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, [loading, isTestFinished]);

  const handleOptionSelect = (option: string) => {
    const currentQ = questions[currentIndex];
    if (!currentQ || answers[currentQ.id]) return;

    setAnswers(prev => ({ ...prev, [currentQ.id]: option }));

    const timeTaken = Math.floor((Date.now() - questionStartTimeRef.current) / 1000); 
    const isCorrect = option === currentQ.correct_option;

    api.submitAnswer(userId, currentQ.id, option, isCorrect, timeTaken);
  };

  const updateVisited = (index: number) => {
      setVisitedIndices(prev => new Set(prev).add(index));
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      const nextIdx = currentIndex + 1;
      setCurrentIndex(nextIdx);
      updateVisited(nextIdx);
      questionStartTimeRef.current = Date.now();

      if (scrollRef.current) {
          const itemWidth = 44; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIdx * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
       if (allQuestionsExhausted.current || isPYQ) {
           handleFinishTest();
       } else if (loadingMore) {
           alert("Fetching more questions...");
       }
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      const prevIdx = currentIndex - 1;
      setCurrentIndex(prevIdx);
      updateVisited(prevIdx);
      questionStartTimeRef.current = Date.now();
    }
  };

  const handleFinishTest = async () => {
      if (isSubmitting) return;
      setIsSubmitting(true);

      const totalQ = questions.length;
      const correctCount = questions.filter(q => answers[q.id] === q.correct_option).length;
      const attemptedCount = Object.keys(answers).length;
      const wrongCount = attemptedCount - correctCount;
      const skippedCount = totalQ - attemptedCount;

      const submissionData: TestSubmission = {
          userId: userId,
          subject: subject,
          testType: isPYQ ? 'PYQ' : 'Infinity',
          totalQuestions: totalQ,
          correct: correctCount,
          wrong: wrongCount,
          skipped: skippedCount,
          timeTaken: elapsedTime, 
          date: new Date().toISOString()
      };

      if (userId) {
          await api.submitTestResult(submissionData);
      }

      setIsTestFinished(true);
      setIsSubmitting(false);
  };

  const formatTime = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    const s = totalSeconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getTxt = (en: string | null, hi: string | null) => lang === 'hi' ? (hi || en) : en;

  if (isTestFinished) {
      const totalQuestions = questions.length;
      const attemptedCount = Object.keys(answers).length;
      const correctCount = questions.filter(q => answers[q.id] === q.correct_option).length;
      const wrongCount = attemptedCount - correctCount;
      const visitedCount = visitedIndices.size;
      const notVisitedCount = totalQuestions - visitedCount;
      const notAnsweredCount = visitedCount - attemptedCount; 
      const score = correctCount; 

      // Back Handler for Result Screen inside Test Component
      // It should trigger onExit directly to go back to previous state
      return (
          <div className="h-[100dvh] flex flex-col bg-white overflow-y-auto font-sans animate-fade-in">
              {/* Analytics Header - Safe Area Fixed */}
              <div className="bg-white px-5 pb-4 pt-safe-header border-b border-gray-100 sticky top-0 z-50 flex justify-between items-center shadow-sm">
                  <h2 className="text-lg font-black text-gray-900">{isPYQ ? `Result - ${pyqYear}` : 'Objective Test'}</h2>
                  <div className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-xs font-bold font-mono">
                      {formatTime(elapsedTime)}
                  </div>
              </div>

              <div className="p-6 pb-24 space-y-6">
                  <h3 className="text-lg font-bold text-gray-900">Test Summary</h3>
                  <div className="bg-gray-50 rounded-2xl p-5 border border-gray-100 shadow-sm space-y-4">
                      <div className="bg-white p-4 rounded-xl flex justify-between items-center shadow-sm border border-gray-100">
                          <span className="text-gray-600 font-medium">Total Questions</span>
                          <span className="text-2xl font-black text-gray-900">{totalQuestions}</span>
                      </div>
                      <div className="space-y-3">
                          <div className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100">
                              <div className="flex items-center gap-3">
                                  <div className="w-3 h-3 rounded-full bg-green-500"></div>
                                  <span className="text-gray-600 font-medium text-sm">Answered</span>
                              </div>
                              <span className="text-lg font-bold text-gray-900">{attemptedCount}</span>
                          </div>
                          <div className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100">
                              <div className="flex items-center gap-3">
                                  <div className="w-3 h-3 rounded-full bg-red-500"></div>
                                  <span className="text-gray-600 font-medium text-sm">Not Answered</span>
                              </div>
                              <span className="text-lg font-bold text-gray-900">{notAnsweredCount}</span>
                          </div>
                      </div>
                  </div>

                  <div className="bg-blue-50 rounded-2xl p-5 border border-blue-100">
                      <div className="flex justify-between items-center mb-4">
                          <span className="text-blue-800 font-bold text-sm uppercase tracking-wider">Evaluation</span>
                          <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-xs font-bold">Marks: +1 / 0</span>
                      </div>
                      <div className="flex gap-4">
                          <div className="flex-1 bg-white p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100">
                              <span className="text-2xl font-black text-green-600">{correctCount}</span>
                              <span className="text-[10px] text-gray-400 font-bold uppercase">Correct</span>
                          </div>
                          <div className="flex-1 bg-white p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100">
                              <span className="text-2xl font-black text-red-500">{wrongCount}</span>
                              <span className="text-[10px] text-gray-400 font-bold uppercase">Wrong</span>
                          </div>
                          <div className="flex-1 bg-white p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100">
                              <span className="text-2xl font-black text-blue-600">{score}</span>
                              <span className="text-[10px] text-gray-400 font-bold uppercase">Score</span>
                          </div>
                      </div>
                  </div>
              </div>

              <div className="fixed bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe z-30 shadow-[0_-5px_20px_rgba(0,0,0,0.05)]">
                  <button onClick={onExit} className="w-full py-4 bg-brand-600 text-white font-bold rounded-xl shadow-lg hover:scale-[1.01] transition-transform">
                      Return to Dashboard
                  </button>
              </div>
          </div>
      )
  }

  if (loading) {
      return (
          <div className="h-screen flex items-center justify-center bg-white flex-col gap-4">
              <div className="w-10 h-10 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-gray-500 font-medium text-sm animate-pulse">Preparing Session...</p>
          </div>
      );
  }

  if (fetchError) {
      return (
          <div className="h-screen flex flex-col items-center justify-center bg-white gap-6 p-6 text-center">
              <p className="text-red-500 font-medium">{fetchError}</p>
              <button onClick={onExit} className="px-6 py-2 bg-gray-100 rounded-lg text-sm font-bold">Back</button>
          </div>
      )
  }

  const currentQ = questions[currentIndex];
  if (!currentQ) return null;

  const currentAnswer = answers[currentQ.id];

  return (
    <div className="flex flex-col h-[100dvh] bg-white relative font-sans text-gray-900 overflow-hidden">

      {/* 1. Header - Fixed Safe Area */}
      <div className="px-4 pb-2 pt-safe-header bg-white flex justify-between items-center shrink-0 shadow-sm border-b border-gray-100 z-10 sticky top-0">
          <div className="flex items-center gap-3">
              <button onClick={handleAppBack} className="p-2 -ml-2 text-gray-500 hover:bg-gray-100 rounded-full">
                  <ArrowLeft size={20} />
              </button>
              <div className="flex flex-col">
                  <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{subject} {isPYQ && `• ${pyqYear}`}</span>
                  <div className="flex items-center gap-1.5 text-gray-800 font-medium leading-none">
                      <Clock size={14} className="text-brand-600" />
                      <span className="font-mono text-sm">{formatTime(elapsedTime)}</span>
                  </div>
              </div>
          </div>

          <button onClick={handleFinishTest} disabled={isSubmitting} className="text-white text-xs font-bold bg-brand-600 px-5 py-2 rounded-lg shadow-md shadow-brand-200 hover:bg-brand-700 transition-colors disabled:opacity-70">
              {isSubmitting ? 'Saving...' : 'Submit'}
          </button>
      </div>

      {/* 2. Top Palette - Below Header */}
      <div className="bg-gray-50/50 border-b border-gray-100 py-2 shrink-0 flex items-center gap-2 px-3">
          <div ref={scrollRef} className="flex-1 overflow-x-auto hide-scrollbar flex items-center gap-2.5 scroll-smooth">
              {questions.map((q, i) => {
                  const isActive = i === currentIndex;
                  const ans = answers[q.id];
                  const isCorrect = ans && ans === q.correct_option;

                  let styleClass = "bg-white border-gray-200 text-gray-500"; 

                  if (ans) {
                      styleClass = isCorrect 
                        ? "bg-green-100 border-green-500 text-green-700" 
                        : "bg-blue-100 border-blue-500 text-blue-700";
                  } else if (isActive) {
                      styleClass = "border-brand-600 text-brand-600 ring-1 ring-brand-100";
                  }

                  return (
                    <button 
                        key={i} 
                        onClick={() => { setCurrentIndex(i); updateVisited(i); }}
                        className={`w-9 h-9 shrink-0 rounded-lg flex items-center justify-center text-sm font-bold border transition-all ${styleClass}`}
                    >
                        {i + 1}
                    </button>
                  )
              })}
              {loadingMore && <div className="w-4 h-4 border-2 border-brand-600 border-t-transparent rounded-full animate-spin shrink-0"></div>}
          </div>
          <div className="h-6 w-[1px] bg-gray-200 mx-1"></div>
          <div className="text-[10px] font-bold text-gray-400">{currentIndex + 1}/{questions.length}</div>
      </div>

      {/* 3. Question Area - Scrollable */}
      <div className="flex-1 overflow-y-auto p-5 pb-32 bg-white w-full">

          <div className="flex justify-between items-start mb-4">
              <span className="font-bold text-gray-400 text-[10px] uppercase tracking-wider bg-gray-100 px-2 py-1 rounded">Question {currentIndex + 1}</span>
              <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-brand-50 px-3 py-1 rounded-full border border-brand-100 text-[10px] font-bold text-brand-700">
                  {lang === 'en' ? 'ENG' : 'HIN'}
              </button>
          </div>

          {/* Question Text - Break Words for Mobile */}
          <div className="mb-4">
              <p className="text-lg font-bold text-gray-900 leading-relaxed font-serif break-words">
                  {getTxt(currentQ.question_text_en, currentQ.question_text_hi)}
              </p>
          </div>

          <div className="flex items-center gap-2 mb-6">
              <span className="px-2 py-0.5 rounded bg-gray-100 text-[9px] font-bold text-gray-500 border border-gray-200 w-fit">
                  +1.0 Marks
              </span>
              {currentQ.exam_year && (
                  <span className="px-2 py-0.5 rounded bg-amber-50 text-[9px] font-bold text-amber-700 border border-amber-100 w-fit flex items-center gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span> {currentQ.exam_year}
                  </span>
              )}
          </div>

          {/* Options */}
          <div className="space-y-4">
              {['A', 'B', 'C', 'D'].map((opt) => {
                  const optionText = getTxt(
                      currentQ[`option_${opt.toLowerCase()}_en` as keyof Question] as string,
                      currentQ[`option_${opt.toLowerCase()}_hi` as keyof Question] as string
                  );

                  const isSelected = currentAnswer === opt;
                  const isCorrectAnswer = currentQ.correct_option === opt;

                  let cardClass = "bg-white border-gray-200 text-gray-600 hover:border-gray-300";
                  let circleClass = "bg-gray-100 text-gray-500 border-gray-200";

                  if (currentAnswer) {
                      if (isCorrectAnswer) {
                          cardClass = "bg-green-50 border-green-500 text-green-800";
                          circleClass = "bg-green-500 text-white border-green-500";
                      } else if (isSelected && !isCorrectAnswer) {
                          cardClass = "bg-blue-50 border-blue-500 text-blue-800";
                          circleClass = "bg-blue-500 text-white border-blue-500";
                      } else {
                          cardClass = "opacity-50 border-gray-100";
                      }
                  }

                  return (
                      <div 
                        key={opt} 
                        onClick={() => handleOptionSelect(opt)}
                        className={`p-4 rounded-xl border-2 flex items-start gap-4 cursor-pointer transition-all active:scale-[0.98] ${cardClass}`}
                      >
                          <div className={`w-6 h-6 rounded-full border flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 transition-colors ${circleClass}`}>
                              {opt}
                          </div>
                          <div className="text-sm font-medium leading-snug break-words flex-1">
                              {optionText}
                          </div>
                      </div>
                  )
              })}
          </div>

      </div>

      {/* 4. Footer Buttons - Fixed Safe Area */}
      <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe z-20 flex items-center justify-between gap-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
          <div className="w-full flex gap-4 pb-2">
            <button 
                onClick={handlePrev} 
                disabled={currentIndex === 0}
                className="px-6 py-3 rounded-xl font-bold text-brand-600 bg-white border-2 border-brand-600 disabled:opacity-50 disabled:border-gray-200 disabled:text-gray-400 transition-colors w-1/3 text-sm"
            >
                Prev
            </button>

            <button 
                onClick={handleNext}
                className="px-6 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 hover:bg-brand-700 transition-transform active:scale-95 w-2/3 text-sm"
            >
                {currentIndex === questions.length - 1 && (allQuestionsExhausted.current || isPYQ) ? 'Finish' : 'Next'}
            </button>
          </div>
      </div>

      {/* --- EXIT MODAL --- */}
      <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl"
                >
                    <div className="w-12 h-1 bg-gray-200 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mb-4">
                            <AlertTriangle className="text-red-500" size={32} />
                        </div>
                        <p className="text-gray-800 font-bold text-lg">Exit Test?</p>
                        <p className="text-gray-500 text-sm mt-1 max-w-xs leading-relaxed">
                            Your progress will be saved, but the test session will end.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-gray-200 text-gray-700 font-bold hover:bg-gray-50 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-200 hover:bg-brand-700 transition-colors"
                        >
                            Resume
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>

    </div>
  );
};

