// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false);
  const [pyqRestoreSubject, setPyqRestoreSubject] = useState<string | null>(null); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  // --- 1. GLOBAL STATUS BAR MANAGEMENT ---
  useStatusBar();

  // --- DOUBLE BACK TO EXIT LOGIC (HOME SCREEN ONLY) ---
  const isModalsClosed = !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen;

  useBackHandler(() => {
    if (location.pathname === '/' && isModalsClosed) {
        if (exitAttempted) {
            return false; // Let browser exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; // Trap
        }
    }
    return false; // Don't trap if not on home or modals open
  }, location.pathname === '/' && isModalsClosed);

  useEffect(() => {
    let mounted = true;

    // Failsafe timeout to prevent infinite loading screen
    const timeout = setTimeout(() => {
        if (mounted && isAppInitializing) {
            console.warn("Session restore timed out - forcing app load");
            setIsAppInitializing(false);
        }
    }, 3000); // 3 seconds max wait

    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();

        if (mounted) {
            if (session) {
                setSession(session);
                if (session.user?.id) {
                    fetchProfile(session.user.id).catch(err => console.error("Profile fetch error:", err));
                }
            }
            setIsAppInitializing(false);
        }
      } catch (error) {
        console.error("Critical session failure:", error);
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session && session.user?.id) {
          fetchProfile(session.user.id).catch(console.error);
      } else {
          setUserProfile(null);
      }
      setIsAppInitializing(false);
    });

    return () => { 
        mounted = false; 
        clearTimeout(timeout);
        subscription.unsubscribe(); 
    };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  // --- STATE RESTORATION LOGIC ---
  useEffect(() => {
    const state = location.state as any;

    // 1. Restore Infinity Practice State
    if (state && state.returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      // Clear state after restoring
      window.history.replaceState({}, document.title);
    } 
    // 2. Restore PYQ State
    else if (state && state.returnTo === 'pyq') {
        setPyqInitialTab(state.tab || 'objective');
        if(state.subject) setPyqRestoreSubject(state.subject);
        setInstantOpen(true); 
        setPYQOpen(true);
        window.history.replaceState({}, document.title);
    }
    else {
      setInfinityInstantOpen(false);
      setInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  const fetchProfile = async (userId: string) => {
    if (!userId) return;
    try {
        const data = await api.getProfile(userId);
        if (!data) {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                const fullName = user?.user_metadata?.full_name || 'Student';
                const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
                const newProfile = await api.createProfile(userId, fullName, avatarUrl);
                if (newProfile) setUserProfile(newProfile);
            }
        } else {
            setUserProfile(data);
        }
    } catch (e) {
        console.error("Error fetching profile", e);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams, { replace: true });
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-600' : 'text-gray-400 hover:text-gray-600'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-[#f8faff] font-sans relative shadow-2xl overflow-hidden text-gray-900">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-gray-50 flex justify-between items-center sticky top-0 z-30 border-b border-gray-200 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-600 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-white p-0.5 border border-gray-200 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img 
                            src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.email ?? 'student'}`} 
                            className="w-full h-full rounded-full" 
                            alt="User" 
                        />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' })} 
                                onOpenPYQ={() => { 
                                    setInstantOpen(false); 
                                    setPyqInitialTab('objective'); 
                                    setPyqRestoreSubject(null);
                                    setPYQOpen(true); 
                                }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id);
                                    // RESTORE STATE: Return to PYQ Modal in Objective Tab, BUT DO NOT SELECT A SUBJECT
                                    navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'objective' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => {
                                     // RESTORE STATE: Return to PYQ Modal in Subjective Tab, BUT DO NOT SELECT A SUBJECT
                                     navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'subjective' } });
                                }}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${activeSubject}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    const subjectParam = infinityConfig?.subject ? `&subject=${encodeURIComponent(infinityConfig.subject)}` : '';
                                    // RESTORE STATE: Return to Infinity Modal
                                    navigate(`/?mode=infinity${subjectParam}`, { replace: true, state: { returnTo: 'infinity' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <Navigate to="/" replace />
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => setSearchParams({}, { replace: true })} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            initialSubject={pyqRestoreSubject}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id || ''} 
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-gray-100 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-gray-900 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-lg">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Atom, FlaskConical, Calculator, Dna, Languages, BookType, Sparkles } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

const subjectsList = [
  { name: 'Physics', icon: Atom, color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-teal-600', bg: 'bg-teal-50', border: 'border-teal-100' },
  { name: 'Maths', icon: Calculator, color: 'text-indigo-600', bg: 'bg-indigo-50', border: 'border-indigo-100' },
  { name: 'Biology', icon: Dna, color: 'text-rose-600', bg: 'bg-rose-50', border: 'border-rose-100' },
  { name: 'Hindi', icon: Languages, color: 'text-orange-600', bg: 'bg-orange-50', border: 'border-orange-100' },
  { name: 'English', icon: BookType, color: 'text-violet-600', bg: 'bg-violet-50', border: 'border-violet-100' },
];

const yearsList = Array.from({ length: 16 }, (_, i) => 2010 + i).reverse();

interface PYQDashboardProps {
  isOpen: boolean;
  onClose: () => void;
  initialTab?: 'objective' | 'subjective';
  initialSubject?: string | null;
  instantOpen?: boolean;
  onSelectYear: (subject: string, year: number, type: 'objective' | 'subjective') => void;
}

export const PYQDashboard: React.FC<PYQDashboardProps> = ({ 
    isOpen, 
    onClose, 
    onSelectYear, 
    initialTab = 'objective', 
    initialSubject = null,
    instantOpen = false 
}) => {
  const [activeTab, setActiveTab] = useState<'objective' | 'subjective'>(initialTab);
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject);

  useEffect(() => {
    if (isOpen) {
      setActiveTab(initialTab);
      // Explicitly set subject to null if initialSubject is null, effectively resetting the view
      setSelectedSubject(initialSubject);
    }
  }, [isOpen, initialTab, initialSubject]);

  // --- STRICT HIERARCHY NAVIGATION ---
  const handleAppBack = () => {
    if (!isOpen) return false;

    // 1. If Subject Selected (Year View) -> Go to Subject Selection
    if (selectedSubject) {
      setSelectedSubject(null);
      return true; // Trap
    }

    // 2. If Subjective Tab active -> Go to Objective Tab
    if (activeTab === 'subjective') {
        setActiveTab('objective');
        return true; // Trap
    }

    // 3. If Subject Selection (Objective) -> Close Modal (Go Home)
    onClose();
    return true; // Trap
  };

  useBackHandler(handleAppBack, isOpen);

  const handleSubjectClick = (subject: string) => {
    setSelectedSubject(subject);
  };

  const handleYearClick = (year: number) => {
    if (selectedSubject) {
      onSelectYear(selectedSubject, year, activeTab);
    }
  };

  return (
    <AnimatePresence>
        {isOpen && (
            <>
                <motion.div 
                    initial={{ opacity: instantOpen ? 0.5 : 0 }} 
                    animate={{ opacity: 0.5 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 bg-black z-40" 
                />

                <motion.div
                    initial={{ x: instantOpen ? 0 : "100%" }}
                    animate={{ x: 0 }}
                    exit={{ x: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300 }}
                    className="fixed inset-y-0 right-0 w-full max-w-md bg-[#f8faff] z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans"
                >
                    <div className="absolute inset-0 z-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                    {/* Header with Safe Area (pt-safe-header) */}
                    <div className="px-5 pb-4 pt-safe-header bg-white/80 backdrop-blur-sm border-b border-gray-100 flex items-center gap-3 sticky top-0 z-50 shadow-sm shrink-0">
                        <button onClick={handleAppBack} className="w-9 h-9 flex items-center justify-center rounded-full bg-gray-50 text-gray-600 hover:bg-gray-100 border border-gray-200 transition-colors -ml-1 active:scale-95">
                            <ChevronLeft size={24} />
                        </button>
                        <h2 className="text-xl font-black text-gray-900 tracking-tight">Practice PYQs</h2>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 pb-24 z-10 hide-scrollbar pb-safe">

                        {/* Tabs */}
                        <div className="flex bg-white p-1.5 rounded-2xl mb-8 border border-gray-100 shadow-sm isolate">
                        {(['objective', 'subjective'] as const).map((tab) => {
                            const isActive = activeTab === tab;
                            return (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`flex-1 py-3 text-sm font-bold text-center relative transition-colors duration-200 ${isActive ? 'text-white' : 'text-gray-500 hover:text-gray-700'}`}
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                {isActive && (
                                <motion.div
                                    layoutId="active-tab-pill"
                                    className="absolute inset-0 bg-gray-900 rounded-xl shadow-md -z-10"
                                    transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                />
                                )}
                                <span className="relative z-10 capitalize">{tab}</span>
                            </button>
                            );
                        })}
                        </div>

                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 pl-1">Select Subject</h3>

                        <div className="relative min-h-[400px]"> 
                            <AnimatePresence mode='wait' initial={false}>
                                <motion.div
                                    key={activeTab}
                                    initial={{ x: 10, opacity: 0 }}
                                    animate={{ x: 0, opacity: 1 }}
                                    exit={{ x: -10, opacity: 0 }}
                                    transition={{ duration: 0.2 }}
                                    className="grid grid-cols-2 gap-4 w-full"
                                >
                                {subjectsList.map((sub) => (
                                    <div 
                                    key={sub.name} 
                                    onClick={() => handleSubjectClick(sub.name)}
                                    className={`bg-white p-4 rounded-2xl border ${sub.border} shadow-sm hover:shadow-md active:scale-[0.97] transition-all cursor-pointer flex flex-col justify-between h-40 group relative overflow-hidden`}
                                    >
                                        <div className={`absolute inset-0 ${sub.bg} opacity-0 group-hover:opacity-50 transition-opacity duration-300`}></div>
                                        <div className="relative z-10">
                                            <div className={`w-10 h-10 rounded-xl ${sub.bg} flex items-center justify-center ${sub.color} mb-3 border ${sub.border}`}>
                                                <sub.icon size={20} strokeWidth={2.5} />
                                            </div>
                                            <span className="font-black text-gray-800 text-lg tracking-tight block">{sub.name}</span>
                                            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wide">BSEB 2010-2025</span>
                                        </div>
                                        <div className="relative z-10 flex items-center gap-1 text-[10px] font-bold text-gray-500 group-hover:text-gray-700 transition-colors mt-auto pt-2 border-t border-gray-50">
                                            <Sparkles size={10} className="text-yellow-500" />
                                            <span>Practice PYQs</span>
                                        </div>
                                    </div>
                                ))}
                                </motion.div>
                            </AnimatePresence>
                        </div>
                    </div>

                    <AnimatePresence>
                        {selectedSubject && (
                        <>
                            <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 0.3 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setSelectedSubject(null)}
                            className="absolute inset-0 bg-black z-40"
                            />

                            <motion.div
                            initial={{ y: "100%" }}
                            animate={{ y: 0 }}
                            exit={{ y: "100%" }}
                            transition={{ type: "spring", damping: 25, stiffness: 300 }}
                            className="absolute bottom-0 left-0 right-0 z-50 rounded-t-[2rem] overflow-hidden"
                            >
                            <div className="bg-white/90 backdrop-blur-xl p-6 pb-safe border-t border-gray-200 shadow-[0_-10px_40px_rgba(0,0,0,0.1)]">
                                <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 mt-2"></div>
                                <h3 className="text-xl font-black text-gray-900 mb-2 text-center">Select Year</h3>
                                <p className="text-gray-500 text-sm text-center mb-6">
                                Practice <span className="font-bold text-gray-900 capitalize">{activeTab}</span> PYQs for <span className="font-bold text-brand-600">{selectedSubject}</span>
                                </p>
                                <div className="flex overflow-x-auto gap-3 pb-6 px-2 hide-scrollbar snap-x">
                                {yearsList.map((year) => (
                                    <button
                                    key={year}
                                    onClick={() => handleYearClick(year)}
                                    className="snap-center shrink-0 w-20 h-14 rounded-2xl bg-white border border-gray-200 shadow-sm hover:border-brand-300 hover:shadow-md flex items-center justify-center text-lg font-bold text-gray-700 transition-all active:scale-95 active:bg-gray-50"
                                    >
                                    {year}
                                    </button>
                                ))}
                                </div>
                            </div>
                            </motion.div>
                        </>
                        )}
                    </AnimatePresence>
                </motion.div>
            </>
        )}
    </AnimatePresence>
  );
};

