    const [chapters, setChapters] = useState<{en: string, hi: string, count: number}[]>([]);
    const [loading, setLoading] = useState(false);

    // Navigation Handler for Practice Screen
    useBackHandler(() => {
        if (selectedSubject) {
            setSearchParams({}); // Go back to subject list
            return true; // Trap
        }
        navigate('/'); // Go home
        return true;
    }, true);

    useEffect(() => {
      api.getSubjects().then(setSubjects);
    }, []);

    useEffect(() => {
      if (selectedSubject) {
          setLoading(true);
          api.getChapterStats(selectedSubject).then(data => {
              setChapters(data);
              setLoading(false);
          });
