// Practice Screen (Route /practice)
const PracticeScreen = ({ onSelectChapter, navigate, profile }: { onSelectChapter: (subject: string, chapter: string) => void, navigate: any, profile: Profile | null }) => {
    const [subjects, setSubjects] = useState<string[]>([]);
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedSubject = searchParams.get('subject');

    const [chapters, setChapters] = useState<{en: string, hi: string, count: number}[]>([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
      api.getSubjects().then(setSubjects);
    }, []);

    useEffect(() => {
      if (selectedSubject) {
          setLoading(true);
          api.getChapterStats(selectedSubject).then(data => {
              setChapters(data);
              setLoading(false);
          });
      }
    }, [selectedSubject]);

    // Stack Logic: Chapter List -> Subject List -> Home
    const handleAppBack = () => {
        if (selectedSubject) {
            setSearchParams({}, { replace: true }); 
            return true; 
        } else {
            navigate('/'); 
            return true; 
        }
    };

    useBackHandler(handleAppBack, true); 

    return (
        <div className="h-full flex flex-col bg-white">
            <div className="sticky top-0 z-50 px-5 pb-3 pt-safe-header bg-white/90 backdrop-blur-md flex justify-between items-center border-b border-gray-100 shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={handleAppBack} className="text-slate-600 hover:text-slate-900 transition-colors p-1 -ml-1 rounded-full active:bg-gray-100">
                        <i className="fa-solid fa-chevron-left text-xl"></i>
                    </button>
                    <h2 className="text-xl font-black text-slate-900 tracking-tight">
                        {selectedSubject || 'Practice'}
                    </h2>
                </div>
                <div className="flex items-center gap-1 text-brand-600 font-black">
                    <i className="fa-solid fa-bolt text-xs"></i>
                    <span>{profile?.weekly_xp || 0}</span>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto hide-scrollbar p-5 pb-24 animate-fade-in bg-gray-50/50">
                {!selectedSubject ? (
                    <>
                        <h2 className="text-2xl font-black text-slate-900 mb-6 px-1">Select <span className="text-brand-600">Subject</span></h2>
                        <div className="grid grid-cols-2 gap-4">
                            {subjects.map(sub => (
                                <div key={sub} onClick={() => setSearchParams({ subject: sub }, { replace: true })} className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm flex flex-col items-center justify-center gap-3 cursor-pointer active:scale-95 transition-all hover:shadow-lg hover:border-brand-200 group relative overflow-hidden">
                                    <div className="absolute top-0 right-0 w-16 h-16 bg-brand-50 rounded-full blur-2xl -mr-8 -mt-8 group-hover:bg-brand-100 transition-colors"></div>
                                    <SubjectIcon subject={sub} />
                                    <span className="font-bold text-slate-700 text-sm group-hover:text-brand-700 transition-colors">{sub}</span>
                                </div>
                            ))}
                        </div>
                    </>
                ) : (
                    <div className="space-y-3">
                        {loading ? (
                            <div className="text-center p-10 text-slate-400 text-sm font-bold animate-pulse">Loading chapters...</div>
                        ) : (
                            chapters.map((chap, idx) => (
                                <div key={idx} onClick={() => onSelectChapter(selectedSubject, chap.en)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm active:scale-[0.98] transition-all flex items-center justify-between cursor-pointer hover:border-brand-200 hover:shadow-md group">
                                    <div className="flex-1 pr-4">
                                        <h4 className="font-bold text-slate-800 text-sm group-hover:text-brand-700 transition-colors leading-snug">
                                            {idx + 1}. {chap.en}
                                        </h4>
                                        {chap.hi && <p className="text-xs text-slate-400 mt-1 font-medium">{chap.hi}</p>}
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors shrink-0">
                                        <i className="fa-solid fa-chevron-right text-xs"></i>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

// Result Screen
const ResultScreen = ({ stats, onHome }: { stats: any, onHome: () => void }) => {
    useBackHandler(() => { onHome(); return true; });
    if(!stats) return <div className="h-screen flex items-center justify-center bg-white"><div className="w-8 h-8 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div></div>;
    const score = stats.correct * 1; 
    return (
        <div className="h-[100dvh] overflow-y-auto bg-white p-6 animate-slide-up pb-safe flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-brand-50 rounded-full flex items-center justify-center mb-6 shadow-inner animate-bounce">
                <i className="fa-solid fa-trophy text-5xl text-brand-600"></i>
            </div>
            <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Test Completed</h2>
            <p className="text-slate-500 font-medium mb-10">Great job! Here is your performance summary.</p>

            <div className="bg-gray-50 rounded-[2.5rem] p-8 w-full mb-8 border border-gray-100 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-brand-400 to-purple-500"></div>
                <div className="text-7xl font-black mb-1 text-transparent bg-clip-text bg-gradient-to-b from-brand-600 to-brand-800">{score}</div>
                <div className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-8">Total Score</div>

                <div className="grid grid-cols-2 gap-4 w-full">
                    <div className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm flex flex-col items-center">
                        <p className="text-3xl font-black text-emerald-500 mb-1">{stats.correct}</p>
                        <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Correct</p>
                    </div>
                    <div className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm flex flex-col items-center">
                        <p className="text-3xl font-black text-rose-500 mb-1">{stats.wrong}</p>
                        <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Wrong</p>
                    </div>
                </div>
            </div>

            <button onClick={onHome} className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl shadow-xl shadow-slate-900/20 hover:scale-[1.02] active:scale-95 transition-all text-lg">Return to Dashboard</button>
        </div>
    );
};

// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);
  const [infinityRestoreStep, setInfinityRestoreStep] = useState<number | undefined>(undefined);
  const [infinityRestoreSubject, setInfinityRestoreSubject] = useState<string | null>(null);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false);
  const [pyqRestoreSubject, setPyqRestoreSubject] = useState<string | null>(null); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  useStatusBar();

  // --- DOUBLE BACK TO EXIT LOGIC ---
  useBackHandler(() => {
    if (location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen) {
        if (exitAttempted) {
            return false; // Exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; 
        }
    }
    return false; 
  }, location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen);

  useEffect(() => {
    let mounted = true;
    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (mounted && session) {
            setSession(session);
            fetchProfile(session.user.id).catch(console.error);
        }
      } catch (error) { console.error(error); } 
      finally { if (mounted) setIsAppInitializing(false); }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session) fetchProfile(session.user.id).catch(console.error);
      else setUserProfile(null);
      setIsAppInitializing(false);
    });
    return () => { mounted = false; subscription.unsubscribe(); };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  // RESTORE STATE LOGIC FOR MODALS
  useEffect(() => {
    const state = location.state as any;

    // 1. Restore Infinity Practice State (Test -> Chapter Select)
    if (state && state.returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      setInfinityRestoreSubject(state.subject); // Go to Step 2 (Chapter Select)
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      window.history.replaceState({}, document.title);
    } 
    // 2. Restore PYQ State (Test -> Year/Subject Select)
    else if (state && state.returnTo === 'pyq') {
        setPyqInitialTab(state.tab || 'objective');
        if(state.subject) setPyqRestoreSubject(state.subject);
        setInstantOpen(true); 
        setPYQOpen(true);
        window.history.replaceState({}, document.title);
    }
    else {
      setInfinityInstantOpen(false);
      setInstantOpen(false);
      setInfinityRestoreSubject(null);
      setPyqRestoreSubject(null);
    }
  }, [location, searchParams, setSearchParams]);

  const fetchProfile = async (userId: string) => {
    const data = await api.getProfile(userId);
    if (!data) {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const fullName = user?.user_metadata?.full_name || 'Student';
            const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/9.x/notionists/svg?seed=${userId}`;
            await api.createProfile(userId, fullName, avatarUrl);
            const newProfile = await api.getProfile(userId);
            if (newProfile) setUserProfile(newProfile);
        }
    } else {
        setUserProfile(data);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams, { replace: true });
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-1 transition-all ${isActive ? 'text-brand-600' : 'text-slate-400 hover:text-slate-600'}`}>
            <i className={`fa-solid ${icon} text-xl mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-[#f8faff] font-sans relative shadow-2xl overflow-hidden text-slate-900">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-white/90 backdrop-blur-xl flex justify-between items-center sticky top-0 z-30 border-b border-gray-100 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    <div className="flex flex-col items-end">
                        <span className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-600 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-white p-0.5 border border-gray-200 cursor-pointer shadow-sm active:scale-95 transition-transform" onClick={() => setDashboardOpen(true)}>
                        <img 
                            src={userProfile?.avatar_url || `https://api.dicebear.com/9.x/notionists/svg?seed=${session?.user?.email}`} 
                            className="w-full h-full rounded-full" 
                            alt="User" 
                        />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => { setInfinityRestoreSubject(null); setSearchParams({ mode: 'infinity' }, { replace: true }); }} 
                                onOpenPYQ={() => { setInstantOpen(false); setPyqInitialTab('objective'); setPyqRestoreSubject(null); setPYQOpen(true); }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id);
                                    const subject = new URLSearchParams(location.search).get('subject');
                                    // RESTORE STATE: Return to PYQ Modal -> Objective Tab -> Specific Subject (Year Popup)
                                    navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'objective', subject: subject } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => {
                                     const subject = new URLSearchParams(location.search).get('subject');
                                     // RESTORE STATE: Return to PYQ Modal -> Subjective Tab -> Specific Subject
                                     navigate('/', { replace: true, state: { returnTo: 'pyq', tab: 'subjective', subject: subject } });
                                }}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        // Go back to practice subject page
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    // RESTORE STATE: Return to Infinity Modal -> Step 2 (Chapter Select)
                                    navigate(`/?mode=infinity`, { replace: true, state: { returnTo: 'infinity', subject: infinityConfig.subject } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <div className="p-10 text-center">Loading...</div>
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => setSearchParams({}, { replace: true })} 
            userId={session?.user?.id}
            initialSubject={infinityRestoreSubject || searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            initialSubject={pyqRestoreSubject}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id || ''} 
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-white text-slate-900 px-6 py-3 rounded-full text-sm font-bold shadow-2xl z-[60] border border-gray-100 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-slate-900 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 flex justify-around py-2 pb-safe-offset-2 z-40 shadow-[0_-5px_20px_rgba(0,0,0,0.03)]">
                <div className="pb-safe flex w-full justify-around pt-2">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Check, FlaskConical, Atom, Calculator, Dna, Languages, BookType } from 'lucide-react';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityPracticeModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  onStartSession: (subject: string, chapters: string[]) => void;
  initialSubject?: string | null;
  onUpdateSubject?: (subject: string | null) => void;
  instantOpen?: boolean;
}

const subjectsList = [
  { name: 'Maths', icon: Calculator, color: 'text-sky-500', bg: 'bg-white', border: 'border-gray-100' },
  { name: 'Chemistry', icon: FlaskConical, color: 'text-teal-500', bg: 'bg-white', border: 'border-gray-100' },
  { name: 'Physics', icon: Atom, color: 'text-blue-500', bg: 'bg-white', border: 'border-gray-100' },
  { name: 'Biology', icon: Dna, color: 'text-rose-500', bg: 'bg-white', border: 'border-gray-100' },
  { name: 'Hindi', icon: Languages, color: 'text-orange-500', bg: 'bg-white', border: 'border-gray-100' },
  { name: 'English', icon: BookType, color: 'text-violet-500', bg: 'bg-white', border: 'border-gray-100' },
];

export const InfinityPracticeModal: React.FC<InfinityPracticeModalProps> = ({ 
  isOpen, 
  onClose, 
  userId, 
  onStartSession,
  initialSubject,
  onUpdateSubject,
  instantOpen = false
}) => {
  const [selectedSubject, setSelectedSubject] = useState<string | null>(initialSubject || null);
  // Step is derived: If subject is selected, we are on Step 2.
  const step = selectedSubject ? 2 : 1;

  const [chapters, setChapters] = useState<{ en: string, hi: string, count: number }[]>([]);
  const [selectedChapters, setSelectedChapters] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Sync with props when modal opens or initialSubject changes
  useEffect(() => {
    if (isOpen) {
        setSelectedSubject(initialSubject || null);
        if (!initialSubject) setSelectedChapters([]); 
    }
  }, [isOpen, initialSubject]);

  // Back Button Logic: Step 2 -> Step 1 -> Close
  const handleAppBack = () => {
    if (step === 2) {
      setSelectedSubject(null);
      if (onUpdateSubject) onUpdateSubject(null);
      return true; // Trap
    } else {
      onClose(); 
      return true; // Trap
    }
  };

  useBackHandler(handleAppBack, isOpen);

  useEffect(() => {
    if (selectedSubject) {
      setLoading(true);
      api.getChapterStats(selectedSubject).then(data => {
        setChapters(data);
        // Pre-select first 3
        setSelectedChapters(data.slice(0, 3).map(c => c.en));
        setLoading(false);
      });
    }
  }, [selectedSubject]);

  const handleSubjectSelect = (subject: string) => {
    setSelectedSubject(subject);
    if (onUpdateSubject) onUpdateSubject(subject);
  };

  const toggleChapter = (chapterName: string) => {
    setSelectedChapters(prev => 
      prev.includes(chapterName) 
        ? prev.filter(c => c !== chapterName) 
        : [...prev, chapterName]
    );
  };

  const handleStart = async () => {
    if (!selectedSubject) return;
    if (selectedChapters.length < 2) {
