import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Clock, AlertTriangle } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

interface TestInterfaceProps {
  questions: Question[];
  subjectName?: string;
  userId: string;
  onComplete: (stats: { correct: number, wrong: number, skipped: number, totalTime: number }) => void;
  onExit: () => void;
  onAnswerSubmit: (qId: number, option: string, isCorrect: boolean, timeTaken: number) => void;
  defaultLanguage?: 'Hindi' | 'English'; 
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
    questions, 
    subjectName, 
    userId, 
    onComplete, 
    onExit, 
    onAnswerSubmit,
    defaultLanguage = 'English'
}) => {
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [grid, setGrid] = useState<Record<number, { status: string, answer: string | null }>>({});
  const [timer, setTimer] = useState(0); 
  const [showSolution, setShowSolution] = useState(false);
  const [stats, setStats] = useState({ correct: 0, wrong: 0, answered: 0 });
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());
  const [submitting, setSubmitting] = useState(false);

  // Exit Modal State
  const [showExitModal, setShowExitModal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Centralized Logic for Back Action
  const handleNavigationBack = () => {
     if (showExitModal) {
         setShowExitModal(false); // Close Modal if open
         return true; 
     }
     if (!submitting) {
         setShowExitModal(true); // Open Modal
         return true;
     }
     return true; // Trap if submitting
  };

  // Sync Hardware Back Button
  useBackHandler(() => {
    return handleNavigationBack();
  }, !submitting); 

  // Initialize Grid
  useEffect(() => {
    const initialGrid: any = {};
    questions.forEach((_, i) => {
        initialGrid[i] = { status: 'not-visited', answer: null };
    });
    if(initialGrid[0]) initialGrid[0].status = 'not-answered';
    setGrid(initialGrid);
    setQuestionStartTime(Date.now()); 
  }, [questions]);

  // Timer
  useEffect(() => {
    const t = setInterval(() => setTimer(time => time + 1), 1000);
    return () => clearInterval(t);
  }, []);

  const currentQ = questions[currentIndex];
  if (!currentQ) return <div className="p-10 text-center flex flex-col items-center justify-center h-screen bg-white"><div className="w-10 h-10 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div><p className="mt-6 text-slate-400 font-bold text-sm tracking-widest uppercase animate-pulse">Loading Test...</p></div>;

  const currentStatus = grid[currentIndex] || { status: 'not-visited', answer: null };

  const handleOptionSelect = (option: string) => {
    if (showSolution) return; 

    const isCorrect = option === currentQ.correct_option;
    const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000); 

    const newGrid = { ...grid };
    newGrid[currentIndex] = {
        answer: option,
        status: isCorrect ? 'answered' : 'not-answered', 
    };
    setGrid(newGrid);
    setShowSolution(true);

    setStats(s => ({
        ...s,
        answered: s.answered + 1,
        correct: isCorrect ? s.correct + 1 : s.correct,
        wrong: !isCorrect ? s.wrong + 1 : s.wrong
    }));

    onAnswerSubmit(currentQ.id, option, isCorrect, timeTaken);
  };

  const finishTest = async () => {
    if (submitting) return;
    setSubmitting(true);

    let correct = 0, wrong = 0, skipped = 0;
    Object.values(grid).forEach((g: any, i) => {
        const q = questions[i];
        if (g.answer) {
            if (g.answer === q.correct_option) correct++;
            else wrong++;
        } else {
            skipped++;
        }
    });

    onComplete({ correct, wrong, skipped, totalTime: timer });
  };

  const handleNext = () => {
    setShowSolution(false);
    if (currentIndex < questions.length - 1) {
      const nextIndex = currentIndex + 1;
      const newGrid = { ...grid };
      if (newGrid[nextIndex].status === 'not-visited') {
          newGrid[nextIndex].status = 'not-answered';
      }
      setGrid(newGrid);
      setCurrentIndex(nextIndex);
      setQuestionStartTime(Date.now());

      // Auto Scroll Palette
      if (scrollRef.current) {
          const itemWidth = 40; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIndex * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
        finishTest();
    }
  };

  const handlePrev = () => {
      setShowSolution(false);
      if (currentIndex > 0) {
        setCurrentIndex(currentIndex - 1);
        setQuestionStartTime(Date.now());
      }
  }

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getText = (field: string) => {
    const en = currentQ[`${field}_en` as keyof Question] as string;
    const hi = currentQ[`${field}_hi` as keyof Question] as string;
    return lang === 'hi' ? (hi || en) : en;
  };

  const questionsLeft = questions.length - stats.answered;

  return (
    <div className="flex flex-col h-[100dvh] bg-white relative font-sans animate-fade-in overflow-hidden">

        {/* --- HEADER (Fixed with Safe Area) --- */}
        <div className="px-4 pb-3 pt-safe-header bg-white border-b border-gray-100 flex justify-between items-center z-50 sticky top-0 shadow-sm shrink-0">
             <div className="flex items-center gap-3">
                 {/* UI Back Button */}
                 <button onClick={handleNavigationBack} className="text-slate-500 hover:text-slate-800 p-1 -ml-1 rounded-full active:bg-gray-100 transition-colors">
                    <ArrowLeft size={22} />
                 </button>

                 <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-xl border border-gray-200/60 shadow-sm">
                    <Clock size={14} className="text-brand-600" />
                    <span className="font-mono font-bold text-slate-700 text-sm tracking-widest">{formatTime(timer)}</span>
                 </div>
            </div>

            <div className="text-xs text-slate-400 font-bold uppercase tracking-widest truncate max-w-[120px]">{subjectName || 'Test'}</div>

            <button 
                onClick={finishTest} 
                disabled={submitting}
                className="bg-slate-900 text-white px-4 py-2 rounded-xl text-xs font-bold shadow-lg shadow-slate-900/10 hover:scale-105 transition-transform disabled:opacity-50 flex items-center gap-2"
            >
                {submitting && <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div>}
                {submitting ? 'Saving' : 'Submit'}
            </button>
        </div>

        {/* --- LIVE STATS GRID --- */}
        <div className="bg-white border-b border-gray-100 py-3 px-5 flex justify-between items-center text-[10px] font-bold text-slate-500 shrink-0 shadow-[0_2px_10px_-5px_rgba(0,0,0,0.05)] z-40">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500 shadow-emerald-500/50 shadow-sm"></div> {stats.correct} Correct</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-rose-500 shadow-rose-500/50 shadow-sm"></div> {stats.wrong} Wrong</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-slate-300"></div> {questionsLeft} Left</div>
        </div>

        {/* --- HORIZONTAL PALETTE STRIP --- */}
        <div className="bg-gray-50/50 border-b border-gray-100 py-3 shrink-0">
            <div ref={scrollRef} className="flex overflow-x-auto px-4 gap-2.5 hide-scrollbar snap-x scroll-smooth">
                {questions.map((_, i) => {
                    const isCorrect = grid[i]?.answer && grid[i]?.answer === questions[i].correct_option;
                    let bg = 'bg-white text-gray-400 border-gray-200';

                    if (grid[i]?.answer) {
                        if (isCorrect) bg = 'bg-emerald-500 text-white border-emerald-500 shadow-md shadow-emerald-500/20';
                        else bg = 'bg-rose-500 text-white border-rose-500 shadow-md shadow-rose-500/20';
                    } else if (i === currentIndex) {
                        bg = 'ring-1 ring-offset-2 ring-slate-900 border-slate-900 text-white bg-slate-900 shadow-lg';
                    }

                    return (
                        <div key={i} onClick={() => { 
                            setCurrentIndex(i); 
                            setShowSolution(!!grid[i]?.answer);
                            setQuestionStartTime(Date.now());
                        }} className={`snap-center shrink-0 w-10 h-10 rounded-xl flex items-center justify-center text-xs font-bold border transition-all cursor-pointer relative active:scale-95 ${bg}`}>
                            {i + 1}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* --- QUESTION AREA (Scrollable) --- */}
        <div className="flex-1 overflow-y-auto p-6 pb-32 hide-scrollbar w-full bg-[#f8faff]">
            <div className="flex justify-between items-center mb-6">
                 <span className="font-black text-slate-300 text-xs uppercase tracking-[0.2em] bg-white border border-gray-100 px-3 py-1.5 rounded-lg shadow-sm">Question {currentIndex + 1}</span>
                 <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1.5 bg-white px-3 py-1.5 rounded-lg border border-gray-200 text-[10px] font-bold text-slate-600 active:scale-95 transition-transform shadow-sm hover:border-brand-200">
                    <i className="fa-solid fa-language text-brand-600"></i> {lang === 'en' ? 'ENGLISH' : 'HINDI'}
                </button>
            </div>

            {/* Question Text with Word Break */}
            <p className="text-xl font-bold text-slate-900 leading-relaxed mb-6 font-sans break-words tracking-tight">
                {getText('question_text')}
            </p>

            <div className="flex items-center gap-3 mb-8">
                <span className="bg-emerald-50 text-emerald-700 text-[10px] font-bold px-2.5 py-1 rounded-md border border-emerald-100 shadow-sm">
                    +1.0 Marks
                </span>
                <span className="bg-rose-50 text-rose-700 text-[10px] font-bold px-2.5 py-1 rounded-md border border-rose-100 shadow-sm">
                    -0.0 Neg
                </span>
            </div>

            <div className="space-y-4">
                {['A','B','C','D'].map((opt) => {
                    const optText = getText(`option_${opt.toLowerCase()}`);
                    const isSelected = currentStatus.answer === opt;
                    const isCorrect = opt === currentQ.correct_option;

                    let cardClass = "p-5 rounded-2xl border cursor-pointer flex items-start gap-4 transition-all active:scale-[0.99] shadow-sm ";
                    let circleClass = "w-8 h-8 rounded-full border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors mt-0.5 ";

                    if (showSolution) {
                        if(isCorrect) {
                            cardClass += "border-emerald-500 bg-emerald-50 shadow-emerald-500/10";
                            circleClass += "bg-emerald-500 text-white border-emerald-500";
                        } else if (isSelected && !isCorrect) {
                            cardClass += "border-rose-500 bg-rose-50 shadow-rose-500/10";
                            circleClass += "bg-rose-500 text-white border-rose-500";
                        } else {
                            cardClass += "border-gray-100 opacity-60 bg-white";
                            circleClass += "border-gray-200 text-gray-400 bg-gray-50";
                        }
                    } else {
                        cardClass += "border-gray-200 bg-white hover:border-slate-300 hover:shadow-md";
                        circleClass += "border-gray-200 text-gray-400 bg-gray-50";
                    }

                    return (
                        <div key={opt} onClick={() => handleOptionSelect(opt)} className={cardClass}>
                            <div className={circleClass}>{opt}</div>
                            <div className="flex-1 text-base font-medium text-slate-700 break-words leading-relaxed">
                                {optText}
                            </div>
                        </div>
                    )
                })}
            </div>

            {showSolution && (
                <div className="mt-8 p-6 rounded-3xl bg-blue-50 border border-blue-100 animate-slide-up shadow-sm">
                    <div className="flex items-center gap-2 mb-3">
                        <div className="w-6 h-6 bg-blue-100 rounded-full flex items-center justify-center text-blue-600">
                            <i className="fa-solid fa-lightbulb text-sm"></i>
                        </div>
                        <p className="text-xs font-bold text-blue-800 uppercase tracking-wider">Explanation</p>
                    </div>
                    <p className="text-sm text-slate-700 leading-loose break-words">{getText('solution_short') || "No detailed explanation available for this question."}</p>
                </div>
            )}
        </div>

        {/* --- BOTTOM BAR (Fixed & Safe Area) --- */}
        <div className="absolute bottom-0 w-full bg-white border-t border-gray-100 p-4 pb-safe shadow-[0_-10px_40px_rgba(0,0,0,0.05)] z-30 flex items-center gap-4">
            <div className="w-full flex gap-4 pb-2">
                <button onClick={handlePrev} disabled={currentIndex === 0} className="w-1/3 py-4 rounded-2xl font-bold text-slate-500 bg-gray-50 border border-gray-200 disabled:opacity-50 hover:bg-gray-100 transition-colors text-sm">
                    Previous
                </button>

                <button onClick={handleNext} className="flex-1 bg-slate-900 text-white font-bold py-4 rounded-2xl shadow-xl shadow-slate-900/20 hover:scale-[1.02] transition-transform flex items-center justify-center gap-2 active:scale-[0.98] text-sm">
                    {currentIndex === questions.length - 1 ? 'Finish Test' : 'Save & Next'}
                </button>
            </div>
        </div>

        {/* --- EXIT CONFIRMATION MODAL --- */}
        <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.6 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white rounded-t-[2.5rem] z-[60] p-6 pb-safe shadow-2xl"
                >
                    <div className="w-16 h-1.5 bg-gray-200 rounded-full mx-auto mb-8 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-10">
                        <div className="w-20 h-20 bg-rose-50 rounded-full flex items-center justify-center mb-6 border border-rose-100 shadow-sm animate-pulse">
                            <AlertTriangle size={36} className="text-rose-500" />
                        </div>
                        <p className="text-slate-900 font-black text-2xl mb-2">Exit Test?</p>
                        <p className="text-slate-500 text-sm max-w-[260px] leading-relaxed font-medium">
                            Your progress will be lost if you exit without submitting. Are you sure?
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-4 rounded-2xl border-2 border-gray-100 text-slate-600 font-bold hover:bg-gray-50 transition-colors text-sm uppercase tracking-wide"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-4 rounded-2xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-500/30 hover:bg-brand-700 transition-colors text-sm uppercase tracking-wide"
                        >
                            Continue
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>
    </div>
  );
};

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --sat: env(safe-area-inset-top);
  --sab: env(safe-area-inset-bottom);
  --sal: env(safe-area-inset-left);
  --sar: env(safe-area-inset-right);
}

html, body, #root {
  height: 100%;
  width: 100%;
  margin: 0;
  padding: 0;
  background-color: #f8faff;
  /* Use dynamic viewport height for mobile browsers */
  min-height: 100dvh;
  /* HD Text Rendering */
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

/* Safe Area Utilities */
.pt-safe {
  padding-top: var(--sat);
}
.pb-safe {
  padding-bottom: var(--sab);
}
.mt-safe {
  margin-top: var(--sat);
}
.mb-safe {
  margin-bottom: var(--sab);
}

/* 
   YouTube-Style Header Spacing 
   Ensures at least 35px of padding for the status bar, 
   preventing content from being hidden behind the notch 
   even if the browser reports 0px safe area.
*/
.pt-safe-header {
  padding-top: max(env(safe-area-inset-top), 35px);
}

/* Header offset: Standard header height + Safe Area 
   Removed the large offset versions to force use of tighter padding 
   in components directly.
*/
.pt-safe-offset-2 {
  padding-top: calc(var(--sat) + 0.5rem);
}

/* Ensure fade-in animations work */
.animate-fade-in {
  animation: fadeIn 0.5s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

import React, { useState, useEffect, useRef } from 'react';
import { Profile } from '../types';

interface HomeScreenProps {
  profile: Profile | null;
  setComingSoonTitle: (t: string) => void;
  onOpenInfinity: () => void;
  onOpenPYQ: () => void;
  onOpenDashboard: () => void;
  onOpenAchievements: () => void;
  navigate: (path: string) => void;
}

export const HomeScreen: React.FC<HomeScreenProps> = ({ 
  profile, 
  setComingSoonTitle, 
  onOpenInfinity, 
  onOpenPYQ, 
  onOpenDashboard, 
  onOpenAchievements, 
  navigate 
}) => {
  const [activeSlide, setActiveSlide] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  // Swipe Logic State
  const [touchStart, setTouchStart] = useState<number>(0);
  const [touchCurrent, setTouchCurrent] = useState<number>(0);
  const [isDragging, setIsDragging] = useState(false);

  const autoSlideInterval = useRef<ReturnType<typeof setInterval> | null>(null);

  // Slide data - Updated for High Resolution
  const slides = [
    {
      id: 'brand',
      isHero: true,
      bg: 'bg-gray-900', 
      btn: 'Start Practice',
      action: () => navigate('/practice'),
      overlay: 'bg-gradient-to-br from-gray-900 via-gray-800 to-black'
    },
    {
      id: 'mission_2026',
      bg: 'bg-indigo-900',
      image: 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?auto=format&fit=crop&q=100&w=1920', // HD Image
      title: 'Dream 450+ Marks',
      subtitle: 'BSEB 2026 • Starts 2 Feb',
      desc: '25,000+ Objectives.',
      btn: 'Start Journey',
      action: () => navigate('/practice'),
      overlay: 'bg-gradient-to-t from-black via-black/60 to-transparent'
    },
    {
      id: 'builder',
      bg: 'bg-brand-600',
      image: 'https://images.unsplash.com/photo-1555099962-4199c345e5dd?auto=format&fit=crop&q=100&w=1920', // HD Image
      profileImg: 'https://raw.githubusercontent.com/socialinfi321-svgph/superkar-reviews/main/IMG_20260106_085046.jpg', 
      title: 'Prem Kashyap',
      subtitle: 'Builder of Raftaar',
      desc: 'Coding the future of education.',
      btn: 'Donate',
      link: 'https://socialinfi321-svgph.github.io/komal-caterers/',
      overlay: 'bg-gradient-to-t from-black via-black/80 to-transparent'
    },
    {
      id: 'telegram',
      bg: 'bg-blue-500',
      image: null,
      isTelegram: true,
      title: 'Join Telegram',
      subtitle: 'Daily Quizzes',
      desc: 'Get exclusive notes and daily quizzes.',
      btn: 'Join Channel',
      link: 'https://t.me/raftartestseries',
      overlay: 'bg-gradient-to-r from-blue-600/95 to-cyan-500/95'
    }
  ];

  // Auto Slider Logic
  useEffect(() => {
    if (isPaused || isDragging) return;

    autoSlideInterval.current = setInterval(() => {
        setActiveSlide(prev => (prev + 1) % slides.length);
    }, 5000);

    return () => {
        if (autoSlideInterval.current) clearInterval(autoSlideInterval.current);
    };
  }, [slides.length, isPaused, isDragging]);

  // Touch Handlers for Manual Swipe with Drag Visualization
  const onTouchStart = (e: React.TouchEvent) => {
    setIsPaused(true);
    setIsDragging(true);
    setTouchStart(e.targetTouches[0].clientX);
    setTouchCurrent(e.targetTouches[0].clientX);
  }

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchCurrent(e.targetTouches[0].clientX);
  }

  const onTouchEnd = () => {
    setIsDragging(false);
    const diff = touchStart - touchCurrent;
    const threshold = 50; // Minimum px distance to trigger slide change

    if (Math.abs(diff) > threshold) {
        if (diff > 0) {
           // Swipe Left -> Next Slide
           setActiveSlide(prev => (prev + 1) % slides.length);
        } else {
           // Swipe Right -> Prev Slide
           setActiveSlide(prev => (prev - 1 + slides.length) % slides.length);
        }
    }

    // Reset Drag State
    setTouchStart(0);
    setTouchCurrent(0);

    // Resume auto-slide after interaction
    setTimeout(() => setIsPaused(false), 5000);
  }

  // Calculate transform with visual drag offset
  const dragOffset = isDragging ? touchCurrent - touchStart : 0;

  return (
    <div className="space-y-6 pb-24 pt-4 animate-fade-in font-sans tracking-tight">

        {/* Rounded Premium Slider */}
        <div className="px-5">
            <div 
                className="rounded-[2rem] overflow-hidden shadow-2xl shadow-brand-900/20 relative h-[180px] touch-pan-y transform-gpu"
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
            >
                {/* Slider Track */}
                <div 
                    className="flex h-full" 
                    style={{ 
                        transform: `translateX(calc(-${activeSlide * 100}% + ${dragOffset}px))`,
                        transition: isDragging ? 'none' : 'transform 0.5s cubic-bezier(0.2, 0.8, 0.2, 1)'
                    }}
                >
                    {slides.map((slide, idx) => (
                        <div key={idx} className="min-w-full relative h-full flex flex-col justify-end p-6 overflow-hidden select-none">
                            {/* Background & Overlay */}
                            <div className="absolute inset-0 z-0 pointer-events-none">
                                {slide.image ? (
                                    <img src={slide.image} className="w-full h-full object-cover" alt="slide" />
                                ) : (
                                    <div className={`w-full h-full ${slide.bg}`}></div>
                                )}
                                <div className={`absolute inset-0 z-10 ${slide.overlay}`}></div>

                                {/* Telegram Pattern */}
                                {slide.isTelegram && (
                                    <div className="absolute inset-0 opacity-10 grid grid-cols-6 gap-4 p-4 transform -rotate-12">
                                        {[...Array(24)].map((_, i) => (
                                            <i key={i} className="fa-brands fa-telegram text-4xl text-white"></i>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Top Right Profile Image (For Builder Slide) */}
                            {(slide as any).profileImg && (
                                <div className="absolute top-4 right-4 z-20 flex flex-col items-end animate-fade-in">
                                    <div className="w-[110px] h-[110px] rounded-full border-4 border-white/30 shadow-2xl overflow-hidden bg-white/10 backdrop-blur-md">
                                        <img src={(slide as any).profileImg} className="w-full h-full object-cover" alt="Profile" />
                                    </div>
                                </div>
                            )}

                            {/* Content */}
                            {slide.isHero ? (
                                <div className="relative z-20 flex flex-col items-center justify-center h-full text-center">
                                    <div className="flex items-center gap-2 mb-3">
                                        <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-lg transform -rotate-6">
                                            <span className="text-gray-900 font-black text-xl font-sans">R</span>
                                        </div>
                                        <h2 className="text-3xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-blue-200 via-white to-blue-200 drop-shadow-sm">RAFTAAR</h2>
                                    </div>
                                    <div className="flex flex-wrap justify-center gap-2 text-[10px] font-bold text-white/90 uppercase tracking-widest mb-4">
                                        <span className="bg-white/10 px-3 py-1 rounded-full border border-white/10 backdrop-blur-md">Infinity Practice</span>
                                        <span className="bg-white/10 px-3 py-1 rounded-full border border-white/10 backdrop-blur-md">Live Mock Test</span>
                                    </div>
                                    <button onClick={slide.action} className="bg-white text-gray-900 px-8 py-2.5 rounded-full text-xs font-black shadow-lg hover:scale-105 transition-transform uppercase tracking-wider">Start Now</button>
                                </div>
                            ) : (
                                <div className="relative z-20 text-white">
                                    <h2 className="text-2xl font-black mb-1 tracking-tight drop-shadow-md">{slide.title}</h2>
                                    <div className="inline-block bg-white/20 backdrop-blur-md px-3 py-1 rounded-lg text-[10px] font-bold uppercase tracking-widest mb-3 border border-white/20">
                                        {slide.subtitle}
                                    </div>
                                    <p className="text-xs opacity-90 leading-relaxed mb-4 max-w-[85%] font-medium text-gray-100 line-clamp-2">{slide.desc}</p>

                                    {slide.link ? (
                                        <a href={slide.link} target="_blank" rel="noreferrer" className="inline-block bg-white text-gray-900 px-6 py-2.5 rounded-xl text-xs font-bold shadow-md hover:scale-105 transition-transform">
                                            {slide.btn}
                                        </a>
                                    ) : (
                                        <button onClick={slide.action} className="bg-white text-gray-900 px-6 py-2.5 rounded-xl text-xs font-bold shadow-md hover:scale-105 transition-transform">
                                            {slide.btn}
                                        </button>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Dots Indicator */}
                <div className="absolute bottom-5 right-6 z-30 flex gap-1.5">
                    {slides.map((_, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => { setActiveSlide(idx); setIsPaused(true); setTimeout(() => setIsPaused(false), 5000); }}
                            className={`h-1.5 rounded-full transition-all duration-300 cursor-pointer ${activeSlide === idx ? 'w-6 bg-white' : 'w-1.5 bg-white/40'}`}
                        ></div>
                    ))}
                </div>
            </div>
        </div>

        {/* 4-Grid Menu */}
        <div className="px-5">
            <h3 className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mb-4 ml-1 flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-brand-500 rounded-full"></span> Quick Access
            </h3>
            <div className="grid grid-cols-2 gap-4">
                {/* Infinity Practice */}
                <div onClick={onOpenInfinity} className="bg-gradient-to-br from-purple-600 to-indigo-700 p-5 rounded-[2rem] shadow-xl shadow-purple-200 active:scale-95 transition-transform flex flex-col items-center justify-center text-center h-32 cursor-pointer relative overflow-hidden group border border-purple-500/20">
                    <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full blur-2xl -mr-6 -mt-6"></div>
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center mb-3 text-white border border-white/20 shadow-inner group-hover:scale-110 transition-transform">
                        <i className="fa-solid fa-infinity text-2xl"></i>
                    </div>
                    <span className="text-xs font-bold text-white tracking-tight">Infinity Practice</span>
                </div>

                {/* PYQ */}
