                     <div className="absolute bottom-0 right-0 w-24 h-24 bg-white/10 rounded-full blur-2xl -mr-6 -mb-6"></div>
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center mb-3 text-white border border-white/20 shadow-inner group-hover:scale-110 transition-transform">
                        <i className="fa-solid fa-trophy text-2xl"></i>
                    </div>
                    <span className="text-xs font-bold text-white tracking-tight">Achievements</span>
                </div>

                {/* Dashboard */}
                <div onClick={onOpenDashboard} className="bg-gradient-to-br from-blue-600 to-brand-700 p-5 rounded-[2rem] shadow-xl shadow-blue-200 active:scale-95 transition-transform flex flex-col items-center justify-center text-center h-32 cursor-pointer relative overflow-hidden group border border-brand-500/20">
                     <div className="absolute top-0 left-0 w-24 h-24 bg-white/10 rounded-full blur-2xl -ml-6 -mt-6"></div>
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center mb-3 text-white border border-white/20 shadow-inner group-hover:scale-110 transition-transform">
                        <i className="fa-solid fa-chart-pie text-2xl"></i>
                    </div>
                    <span className="text-xs font-bold text-white tracking-tight">My Dashboard</span>
                </div>
            </div>
        </div>

        {/* Featured Series */}
        <div className="px-5">
            <h3 className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mb-4 ml-1 flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-indigo-500 rounded-full"></span> Featured Series
            </h3>
